function g(id){return document.getElementById(id)}
function enterApp(){g('splash').classList.add('hide')}

var theme='dark', nightMode=false, largeMode=false, locked=false;

function toggleTheme(){
  if(nightMode) toggleNight();
  theme=(theme==='dark')?'light':'dark';
  document.documentElement.className=theme;
  g('theme-btn').innerText=theme==='dark'?'☀️':'🌙';
}

function toggleNight(){
  nightMode=!nightMode;
  var body=document.documentElement;
  if(nightMode){
    body.className='night';
    theme='night';
    g('night-btn').classList.add('night-on');
    g('night-btn').innerText='🔴 НОЧЬ';
    // Уменьшить яркость экрана через CSS
    document.body.style.filter='brightness(0.85)';
  } else {
    body.className='dark';
    theme='dark';
    g('night-btn').classList.remove('night-on');
    g('night-btn').innerText='🔴 Ночь';
    document.body.style.filter='';
  }
}

function toggleLarge(){
  largeMode=!largeMode;
  document.body.classList.toggle('large-mode', largeMode);
  g('large-btn').classList.toggle('active', largeMode);
  g('large-btn').innerText=largeMode?'🔠 ВКЛ':'🔠';
}

var lockTaps=0;
function toggleLock(){
  locked=!locked;
  g('lock-overlay').classList.toggle('on', locked);
  g('lock-bar').classList.toggle('on', locked);
  g('lock-btn').innerText=locked?'🔒':'🔓';
  g('lock-btn').classList.toggle('active', locked);
  lockTaps=0;
}
function unlockTap(){
  lockTaps++;
  if(lockTaps>=3) toggleLock();
}

var tabOrder=['avisos','calc','route','mag','meteo','fuel','conv','timer','timecalc','metar','wb','isa','hist','map','efb','zones','ac-su25','ac-yak130','ac-da42','ac-an26','ac-l410','ac-l39'];
var currentTabIdx=0;

function showTab(t){
  var tabs=document.querySelectorAll('.tab');
  var pages=document.querySelectorAll('.page');
  tabs.forEach(function(el,i){
    el.classList.toggle('active',el.getAttribute('onclick').indexOf("'"+t+"'")!==-1);
  });
  pages.forEach(function(el){
    el.classList.toggle('active',el.id==='tab-'+t);
  });
  currentTabIdx=tabOrder.indexOf(t);
  if(t==='route') routeCalc();
  if(t==='map') setTimeout(function(){ initMap(); }, 50);
  if(t==='efb') setTimeout(function(){ efbInit(); }, 50);
  // Aircraft tabs
  if(t.indexOf('ac-') === 0) {
    var acKey = t.replace('ac-','');
    renderACPage(acKey, 'tab-'+t);
  }
  var scroll=document.querySelector('.scroll');
  if(scroll) scroll.scrollTop=0;
  fixScrollHeight();
}

// Flash result on update
function flashResult(id, dangerLevel){
  var el=g(id);
  if(!el) return;
  el.classList.remove('result-updated');
  void el.offsetWidth;
  el.classList.add('result-updated');
  var rc=el.closest('.rc');
  if(rc){
    rc.classList.remove('danger-warn');
    if(dangerLevel) { void rc.offsetWidth; rc.classList.add('danger-warn'); }
    setTimeout(function(){ rc.classList.remove('danger-warn'); }, dangerLevel?3000:0);
  }
}

// Профили ВС
var profiles = {
  su25:   { vias: 550, vcorr: 5, rate: 1800, bank: 30, lur: 7 },
  yak130: { vias: 450, vcorr: 4, rate: 1400, bank: 25, lur: 5 },
  da42:   { vias: 290, vcorr: 0, rate: 60,   bank: 20, lur: 1.5 },
  an26:   { vias: 430, vcorr: 3, rate: 1200, bank: 20, lur: 4 },
  l410:   { vias: 280, vcorr: 3, rate: 320,  bank: 20, lur: 2 },
  l39:    { vias: 400, vcorr: 4, rate: 900,  bank: 25, lur: 3.5 }
};

function setProfile(p) {
  document.querySelectorAll('.prof-btn').forEach(b => b.classList.remove('active'));
  g('prof-'+p).classList.add('active');
  var d = profiles[p];
  g('vias').value = d.vias;
  g('vcorr').value = d.vcorr;
  g('pnr-rate').value = d.rate;
  g('tn-bank').value = d.bank;
  calc();
}

function step(id,v){
  var el=g(id); el.value=Math.max(0,parseFloat(el.value||0)+v); calc();
}

var lastResult={};
function calc(){
  var pu=parseFloat(g('pu').value||0)%360;
  var vias=parseFloat(g('vias').value||0);
  var vcorr=parseFloat(g('vcorr').value||0);
  var wdir=parseFloat(g('wdir').value||0)%360;
  var wspd=parseFloat(g('wspd').value||0);
  var dist=parseFloat(g('dist').value||0);

  var vtas = vias * (1 + vcorr/100);
  var windRad = ((wdir + 180 - pu) * Math.PI) / 180;
  
  var sinUS = (wspd * Math.sin(windRad)) / vtas;
  var errEl = g('err');
  if(Math.abs(sinUS) > 1){
    errEl.classList.add('on'); return;
  } else {
    errEl.classList.remove('on');
  }

  var usRad = Math.asin(sinUS);
  var us = Math.round((usRad * 180) / Math.PI);
  var hdg = (Math.round(pu - us) + 360) % 360;
  var gs = Math.round(vtas * Math.cos(usRad) + wspd * Math.cos(windRad));
  
  var tmin = gs > 0 ? (dist / gs) * 60 : 0;
  
  flashResult('r-drift'); g('r-drift').innerText = (us > 0 ? '+' : '') + us + '°';
  g('r-hdg').innerText = hdg + '°';
  g('r-vtas').innerText = Math.round(vtas) + ' км/ч';
  g('r-gs').innerText = gs + ' км/ч';
  g('r-tmin').innerText = tmin > 0 ? tmin.toFixed(1) + ' мин' : '—';
  
  var s=Math.floor((tmin*60)%60), m=Math.floor(tmin%60), h=Math.floor(tmin/60);
  g('r-thms').innerText = (h<10?'0':'')+h+':'+(m<10?'0':'')+m+':'+(s<10?'0':'')+s;

  lastResult = { pu:pu, vias:vias, wdir:wdir, wspd:wspd, drift:us, hdg:hdg, gs:gs };
  drawRose(pu, hdg, wdir);
}

function drawRose(pu, hdg, wdir){
  var gWind=g('g-wind'), gPath=g('g-path'), gHdg=g('g-hdg');
  gWind.innerHTML=''; gPath.innerHTML=''; gHdg.innerHTML='';
  
  var rWind = ((wdir - 90) * Math.PI) / 180;
  gWind.innerHTML = `<line x1="90" y1="90" x2="${90 + 45*Math.cos(rWind)}" y2="${90 + 45*Math.sin(rWind)}" stroke="#ff4466" stroke-width="2"/>`;
  
  var rPath = ((pu - 90) * Math.PI) / 180;
  gPath.innerHTML = `<line x1="90" y1="90" x2="${90 + 75*Math.cos(rPath)}" y2="${90 + 75*Math.sin(rPath)}" stroke="#00c8ff" stroke-width="2.5"/>`;
  
  var rHdg = ((hdg - 90) * Math.PI) / 180;
  gHdg.innerHTML = `<line x1="90" y1="90" x2="${90 + 70*Math.cos(rHdg)}" y2="${90 + 70*Math.sin(rHdg)}" stroke="#ffb800" stroke-width="1.5" stroke-dasharray="4,2"/>`;
}

// Маршрут (ППМ)
var route = [
  {name:'ППМ1', pu:90, dist:120},
  {name:'ППМ2', pu:150, dist:80},
  {name:'ППМ3', pu:210, dist:160}
];

function routeCalc(){
  var vias=parseFloat(g('rt-vias').value||0);
  var vcorr=parseFloat(g('rt-vcorr').value||0);
  var wdir=parseFloat(g('rt-wdir').value||0);
  var wspd=parseFloat(g('rt-wspd').value||0);
  var vtas = vias * (1 + vcorr/100);
  
  var tbody = g('route-body');
  tbody.innerHTML = '';
  
  route.forEach(function(r, i){
    var windRad = ((wdir + 180 - r.pu) * Math.PI) / 180;
    var sinUS = (wspd * Math.sin(windRad)) / vtas;
    var us = Math.abs(sinUS)<=1 ? Math.round((Math.asin(sinUS)*180)/Math.PI) : 0;
    var hdg = (r.pu - us + 360) % 360;
    var gs = Math.round(vtas * Math.cos((us*Math.PI)/180) + wspd * Math.cos(windRad));
    var t = gs > 0 ? ((r.dist / gs) * 60).toFixed(1) : '—';
    
    // Линейное упреждение разворота (Базовое приближение штурмана)
    var lur = (vtas * 0.005).toFixed(1); 

    tbody.innerHTML += `<tr>
      <td><input type="text" value="${r.name}" style="width:50px; background:transparent; border:none; color:inherit; text-align:center" onchange="route[${i}].name=this.value"></td>
      <td><input type="number" value="${r.pu}" style="width:40px; background:transparent; border:none; color:inherit; text-align:center" onchange="route[${i}].pu=parseInt(this.value); routeCalc()"></td>
      <td><input type="number" value="${r.dist}" style="width:45px; background:transparent; border:none; color:inherit; text-align:center" onchange="route[${i}].dist=parseInt(this.value); routeCalc()"></td>
      <td>${us}°</td><td>${hdg}°</td><td>${gs}</td><td>${t}</td><td>${lur}</td>
      <td><span class="del-row" onclick="delRouteRow(${i})">×</span></td>
    </tr>`;
  });
}

function addRouteRow(){
  route.push({name:'ППМ'+(route.length+1), pu:90, dist:100}); routeCalc();
}
function delRouteRow(i){
  route.splice(i,1); routeCalc();
}
function exportRoute(){
  alert(JSON.stringify(route));
}
function importRoute(){
  var str = prompt("Вставьте JSON-строку маршрута:");
  if(str) { try { route = JSON.parse(str); routeCalc(); } catch(e) { alert("Ошибка парсинга данных"); } }
}

// Магнитный курс & БУ
function convMag(src){
  var ik=parseFloat(g('mag-ik').value||0);
  var sklon=parseFloat(g('mag-sklon').value||0);
  var dev=parseFloat(g('mag-dev').value||0);
  g('mag-mk').innerText = ((ik - sklon + 360) % 360) + '°';
  g('mag-kk').innerText = ((ik - sklon - dev + 360) % 360) + '°';
}
function calcBU(){
  var s1=parseFloat(g('bu-s1').value||1);
  var s2=parseFloat(g('bu-s2').value||1);
  var lbu=parseFloat(g('bu-lbu').value||0);
  var bu = Math.round((lbu / s1) * 57.3);
  var dop = Math.round((lbu / s2) * 57.3);
  g('bu-r1').innerText = bu + '°';
  g('bu-r2').innerText = (bu + dop) + '°';
}

// Метео вкладка
function meteoCalc(){
  var rwy=parseFloat(g('met-rwy').value||0);
  var wdir=parseFloat(g('met-wdir').value||0);
  var wspd=parseFloat(g('met-wspd').value||0);
  var qnh=parseFloat(g('mt-qnh').value||1013);
  var elev=parseFloat(g('mt-elev').value||0);
  var temp=parseFloat(g('mt-temp').value||15);

  var angle = ((wdir - rwy) * Math.PI) / 180;
  g('rwy-cross').innerText = Math.abs(Math.round(wspd * Math.sin(angle))) + ' км/ч';
  g('rwy-head').innerText = Math.round(wspd * Math.cos(angle)) + ' км/ч';

  var qfe = qnh - (elev / 8.5);
  g('mt-qfe').innerText = Math.round(qfe) + ' гПа';

  // Плотность высоты (Density Altitude) приближенная формула ICAO
  var isaTemp = 15 - (elev * 0.0065);
  var densAlt = elev + 36.6 * (temp - isaTemp);
  g('mt-dens-alt').innerText = Math.round(densAlt) + ' м';

  // Wind vane animation
  updateWindVane(wdir, rwy, Math.abs(Math.round(wspd * Math.sin(angle))));
}

function updateWindVane(wdir, rwy, cross){
  var vaneWind = g('vane-wind');
  var vaneRwy = g('vane-rwy');
  if(!vaneWind) return;

  // Rotate wind arrow to wind direction (where wind comes FROM → point arrow FROM that dir)
  var wRad = ((wdir - 90) * Math.PI) / 180;
  var wx2 = 60 + 48 * Math.cos(wRad), wy2 = 60 + 48 * Math.sin(wRad);
  var wx1 = 60 - 22 * Math.cos(wRad), wy1 = 60 - 22 * Math.sin(wRad);
  // arrowhead
  var ah1x = wx2 - 8*Math.cos(wRad-0.4), ah1y = wy2 - 8*Math.sin(wRad-0.4);
  var ah2x = wx2 - 8*Math.cos(wRad+0.4), ah2y = wy2 - 8*Math.sin(wRad+0.4);
  vaneWind.innerHTML = '<line x1="'+wx1+'" y1="'+wy1+'" x2="'+wx2+'" y2="'+wy2+'" stroke="#ff4466" stroke-width="2.5"/>'+
    '<polygon points="'+wx2+','+wy2+' '+ah1x+','+ah1y+' '+ah2x+','+ah2y+'" fill="#ff4466"/>';

  // Rotate runway line
  var rRad = ((rwy - 90) * Math.PI) / 180;
  var rx1 = 60 - 52*Math.cos(rRad), ry1 = 60 - 52*Math.sin(rRad);
  var rx2 = 60 + 52*Math.cos(rRad), ry2 = 60 + 52*Math.sin(rRad);
  vaneRwy.innerHTML = '<line x1="'+rx1+'" y1="'+ry1+'" x2="'+rx2+'" y2="'+ry2+'" stroke="#00c8ff" stroke-width="3" opacity=".5"/>';

  // Crosswind bar visual (max ±15 km/h scale)
  var arrow = g('cross-arrow');
  var label = g('cross-label');
  if(arrow){
    var maxCross = 15;
    var pct = Math.max(-1, Math.min(1, cross / maxCross));
    var centerPct = 50 + pct * 45;
    var color = Math.abs(cross) > 10 ? '#ff4466' : Math.abs(cross) > 6 ? '#ffb800' : '#00e5a0';
    var barW = Math.max(4, Math.abs(pct)*45);
    var barLeft = pct >= 0 ? 50 : 50 - barW;
    arrow.style.width = barW + '%';
    arrow.style.left = barLeft + '%';
    arrow.style.background = color;
    if(label) label.innerText = 'Боковой: ' + cross + ' км/ч' + (Math.abs(cross)>10?' ⚠️ ПРЕВЫШЕНИЕ':'');
    if(Math.abs(cross) > 10) flashResult('rwy-cross', true);
  }
}

function calcInverseWind(){
  var ik=parseFloat(g('inv-ik').value||0);
  var vtas=parseFloat(g('inv-vtas').value||1);
  var fpu=parseFloat(g('inv-fpu').value||0);
  var w=parseFloat(g('inv-w').value||0);

  var ikRad = (ik * Math.PI)/180;
  var fpuRad = (fpu * Math.PI)/180;

  var wx = w * Math.cos(fpuRad) - vtas * Math.cos(ikRad);
  var wy = w * Math.sin(fpuRad) - vtas * Math.sin(ikRad);
  
  var wspd = Math.sqrt(wx*wx + wy*wy);
  var wdir = (Math.atan2(wy, wx) * 180)/Math.PI;
  wdir = (wdir + 360) % 360;

  g('inv-r-wdir').innerText = Math.round(wdir) + '°';
  g('inv-r-wspd').innerText = Math.round(wspd) + ' км/ч';
}

// Топливо и Виражи
function turnCalc(){
  var vtas=parseFloat(g('tn-vtas').value||300) / 3.6; // м/с
  var bank=parseFloat(g('tn-bank').value||25) * Math.PI / 180;
  var angle=parseFloat(g('tn-angle').value||90);
  
  var gConst = 9.81;
  var radius = (vtas * vtas) / (gConst * Math.tan(bank));
  var ny = 1 / Math.cos(bank);
  var omega = (gConst * Math.tan(bank)) / vtas; // рад/с
  var time = (angle * Math.PI / 180) / omega;

  // УУР (Угол упреждения разворота)
  var uur = Math.round((radius * 57.3) / radius); // Упрощенное угловое упреждение

  g('turn-radius').innerText = Math.round(radius) + ' м';
  g('turn-uur').innerText = Math.round(angle * 0.15) + '°'; // Практический расчет штурмана
  g('turn-time').innerText = Math.round(time) + ' сек';
  g('turn-g').innerText = ny.toFixed(2);
  updateHorizon(parseFloat(g('tn-bank').value||0), ny);
  flashResult('turn-g');
}

function updateHorizon(bankDeg, ny){
  var svg = g('horizon-svg');
  if(!svg) return;
  var sky = g('h-sky'), gnd = g('h-gnd'), hor = g('h-horizon'), ptr = g('h-bank-ptr');
  if(!sky) return;
  var cx=80, cy=80, r=68;
  var bankRad = bankDeg * Math.PI / 180;
  // Rotate horizon line and fill
  var cosB = Math.cos(bankRad), sinB = Math.sin(bankRad);
  var hx1 = cx - r*cosB, hy1 = cy - r*sinB;
  var hx2 = cx + r*cosB, hy2 = cy + r*sinB;
  hor.setAttribute('x1', hx1); hor.setAttribute('y1', hy1);
  hor.setAttribute('x2', hx2); hor.setAttribute('y2', hy2);
  // Update sky/ground using transform
  sky.setAttribute('transform','rotate('+bankDeg+','+cx+','+cy+')');
  gnd.setAttribute('transform','rotate('+bankDeg+','+cx+','+cy+')');
  hor.setAttribute('transform','');
  // Bank pointer rotation
  var pRad = bankRad;
  var px = cx + 42*Math.sin(pRad), py = cy - 42*Math.cos(pRad);
  // rotate the pointer triangle
  ptr.setAttribute('transform','rotate('+bankDeg+','+cx+','+cy+')');
  // Label
  var lbl = g('horizon-label');
  if(lbl) lbl.innerText = 'Крен: '+bankDeg+'° · Ny: '+ny.toFixed(2)+(ny>2?' ⚠️':'');
}

function pnrCalc(){
  var fuel=parseFloat(g('pnr-fuel').value||0);
  var rate=parseFloat(g('pnr-rate').value||1);
  var gs=parseFloat(g('pnr-gs').value||1);
  var gsback=parseFloat(g('pnr-gsback').value||1);
  
  var timeTotal = fuel / rate; // в часах
  var dPnr = (timeTotal * gs * gsback) / (gs + gsback);
  var tPnr = (dPnr / gs) * 60;

  g('pnr-dist').innerText = Math.round(dPnr) + ' км';
  g('pnr-time').innerText = Math.round(tPnr) + ' мин';
}

// Конвертер
function convSpeed(src){
  var kmh=g('cv-kmh'), kt=g('cv-kt'), ms=g('cv-ms');
  if(src==='kmh'){ kt.value=(kmh.value/1.852).toFixed(1); ms.value=(kmh.value/3.6).toFixed(1); }
  if(src==='kt'){ kmh.value=(kt.value*1.852).toFixed(1); ms.value=(kt.value*0.514).toFixed(1); }
  if(src==='ms'){ kmh.value=(ms.value*3.6).toFixed(1); kt.value=(ms.value/0.514).toFixed(1); }
}
function convDist(src){
  var m=g('cv-m'), ft=g('cv-ft'), nm=g('cv-nm');
  if(src==='m'){ ft.value=(m.value*3.2808).toFixed(1); nm.value=(m.value/1852).toFixed(3); }
  if(src==='ft'){ m.value=(ft.value/3.2808).toFixed(1); nm.value=(ft.value/6076.1).toFixed(3); }
  if(src==='nm'){ m.value=(nm.value*1852).toFixed(0); ft.value=(nm.value*6076.1).toFixed(0); }
}

// Секундомер
var tInterval, tActive=false, tTime=0;
function tStart(){ if(!tActive){ tActive=true; tInterval=setInterval(function(){ tTime+=10; var ms=Math.floor((tTime%1000)/10), s=Math.floor((tTime/1000)%60), m=Math.floor((tTime/60000)%60), h=Math.floor(tTime/3600000); g('t-disp').innerText=(h<10?'0':'')+h+':'+(m<10?'0':'')+m+':'+(s<10?'0':'')+s; g('t-ms').innerText='.'+(ms<10?'0':'')+ms; },10); } }
function tStop(){ clearInterval(tInterval); tActive=false; }
function tReset(){ clearInterval(tInterval); tActive=false; tTime=0; g('t-disp').innerText='00:00:00'; g('t-ms').innerText='.00'; }

// Калькулятор времени
function timeToSec(str) {
  var p = str.split(':');
  return parseInt(p[0]||0)*3600 + parseInt(p[1]||0)*60 + parseInt(p[2]||0);
}
function secToTime(sec) {
  if (sec < 0) sec = 0;
  var h = Math.floor(sec / 3600), m = Math.floor((sec % 3600) / 60), s = sec % 60;
  return (h<10?'0':'')+h+':'+(m<10?'0':'')+m+':'+(s<10?'0':'')+s;
}
function calcTimeOp(){
  var t1 = timeToSec(g('tm-t1').value);
  var t2 = timeToSec(g('tm-t2').value);
  var op = g('tm-op').value;
  var res = op === 'add' ? t1 + t2 : t1 - t2;
  g('tm-result').innerText = secToTime(res);
}

// История расчетов
var historyData = [];
function saveToHistory(){
  if(!lastResult.hdg) return;
  var d = new Date(), ts = (d.getHours()<10?'0':'')+d.getHours()+':'+(d.getMinutes()<10?'0':'')+d.getMinutes();
  historyData.unshift({ts:ts, data:Object.assign({},lastResult)});
  renderHistory();
}
function renderHistory(){
  var el=g('hist-list'); el.innerHTML='';
  if(!historyData.length){ el.innerHTML='<div class="hist-empty">История пуста</div>'; return; }
  historyData.forEach((h,i)=>{
    el.innerHTML+=`<div class="hist-item">
      <span class="hist-num">#${historyData.length-i} · ${h.ts}</span>
      <div class="hist-main">ПУ <b>${h.data.pu}°</b> · Vпр <b>${h.data.vias}</b> · УС <b>${h.data.drift}°</b> · КУ <b>${h.data.hdg}°</b> · W <b>${h.data.gs}</b></div>
    </div>`;
  });
}
function clearHistory(){ historyData=[]; renderHistory(); }


// ════════════════ METAR / TAF ════════════════
function setMetarIcao(ic){ g('metar-icao').value=ic; fetchMetar(); }

function openMetarTaf(){
  var icao = (g('metar-icao').value||'').trim().toUpperCase();
  if(!icao || icao.length < 2){ alert('Введите код ИКАО'); return; }
  window.open('https://metar-taf.com/metar/' + encodeURIComponent(icao), '_blank');
}

function fetchMetar(){
  var icao = (g('metar-icao').value||'').trim().toUpperCase();
  if(icao.length<4){ alert('Введите 4-буквенный код ИКАО'); return; }

  var panel = g('metar-panel'), tpanel = g('taf-panel');
  g('metar-raw').innerHTML='<span style="color:var(--mu)">⏳ Загрузка...</span>';
  panel.style.display='block';
  tpanel.style.display='none';

  // ── Источник 1: VATSIM (открытый, без CORS, текстовый формат) ──
  var vatsimUrl = 'https://metar.vatsim.net/metar.php?id=' + icao;
  fetch(vatsimUrl)
    .then(function(r){
      if(!r.ok) throw new Error('HTTP '+r.status);
      return r.text();
    })
    .then(function(txt){
      txt = txt.trim();
      if(!txt || txt.length < 10 || txt.indexOf('No METAR') !== -1){
        throw new Error('empty');
      }
      g('metar-raw').innerHTML='<span style="color:var(--ac)">'+txt+'</span>';
      // Парсим вручную из сырой строки
      renderMetarFromRaw(txt);
      panel.style.display='block';
      // TAF через aviationweather как запасной
      fetchTafFallback(icao, tpanel);
    })
    .catch(function(){
      // ── Источник 2: aviationweather.gov (запасной) ──
      var url2 = 'https://aviationweather.gov/api/data/metar?ids='+icao+'&format=json&hours=2';
      fetch(url2)
        .then(function(r){ return r.json(); })
        .then(function(data){
          if(!data || !data.length){
            g('metar-raw').innerHTML='<span style="color:var(--rd)">METAR не найден для <b>'+icao+'</b>.<br>Аэродром не передаёт данные или код неверен.<br><br>Введите METAR вручную в блоке ниже.<br><br><span style="color:var(--mu)">💡 Попробуйте нажать «Открыть на metar-taf.com» ↑</span></span>';
            return;
          }
          var m = data[0];
          var rawText = m.rawOb || m.raw_text || JSON.stringify(m);
          g('metar-raw').innerHTML='<span style="color:var(--ac)">'+rawText+'</span>';
          renderMetarDecoded(m);
          panel.style.display='block';
          fetchTafFallback(icao, tpanel);
        })
        .catch(function(e){
          g('metar-raw').innerHTML='<span style="color:var(--rd)">⚠ Нет доступа к серверам METAR.<br><span style="font-size:10px;color:var(--mu)">Причина: CORS / сеть / блокировка ('+e.message+')</span><br><br>Введите строку METAR вручную в блоке ниже.<br><br><span style="color:var(--mu)">💡 Попробуйте нажать «Открыть на metar-taf.com» ↑</span></span>';
        });
    });
}

function fetchTafFallback(icao, tpanel){
  var tafUrl = 'https://aviationweather.gov/api/data/taf?ids='+icao+'&format=json&time=valid';
  fetch(tafUrl)
    .then(function(r){ return r.json(); })
    .then(function(data){
      if(!data || !data.length){ tpanel.style.display='none'; return; }
      var t = data[0];
      var raw = t.rawTAF || t.raw_text || '';
      raw = raw.replace(/(BECMG|TEMPO|FM\d{6}|PROB\d{2})/g,'<br><span style="color:var(--am)">$1</span>');
      g('taf-raw').innerHTML='<span style="color:var(--gr)">'+raw+'</span>';
      tpanel.style.display='block';
    })
    .catch(function(){ tpanel.style.display='none'; });
}

// Парсинг сырой строки METAR без API
function renderMetarFromRaw(raw){
  var el = g('metar-decoded'); if(!el) return;
  var wind='—', vis='—', cloud='—', temp='—', dew='—', qnh='—';

  // Ветер: dddffMPS или dddffKT
  var wm = raw.match(/\b(\d{3}|VRB)(\d{2,3})(G\d{2,3})?(MPS|KT)\b/);
  if(wm){
    var dir = wm[1]==='VRB'?'ПЕР':wm[1]+'°';
    var spd = parseInt(wm[2]);
    var unit = wm[4]==='MPS'?' м/с':' уз';
    wind = dir+' '+spd+unit;
  }
  // Видимость
  var vm = raw.match(/\b(\d{4})\b/);
  if(vm){ var v=parseInt(vm[1]); vis = v>=9999?'≥10 км':(v>=1000?(v/1000).toFixed(1)+' км':v+' м'); }
  // Темп/точка росы
  var tm = raw.match(/\bM?(\d{2})\/M?(\d{2})\b/);
  if(tm){
    temp = (raw.indexOf('M'+tm[1])!==-1?'-':'')+parseInt(tm[1])+'°C';
    dew  = (raw.indexOf('/M'+tm[2])!==-1?'-':'')+parseInt(tm[2])+'°C';
  }
  // QNH
  var qm = raw.match(/\bQ(\d{4})\b/);
  if(qm) qnh = parseInt(qm[1])+' гПа';
  var qia = raw.match(/\bA(\d{4})\b/);
  if(qia && !qm) qnh = Math.round(parseInt(qia[1])/100*33.8639)+' гПа';
  // Облачность
  var clouds=[], crx=/(FEW|SCT|BKN|OVC)(\d{3})/g, cm;
  while((cm=crx.exec(raw))!==null) clouds.push(cm[1]+' '+parseInt(cm[2])*100+'фт');
  if(raw.indexOf('CAVOK')!==-1) clouds=['CAVOK'];
  cloud = clouds.length?clouds.join(', '):'ясно';

  el.innerHTML=[
    '<div class="rc hi"><span class="rl">Ветер</span><span class="rv lcd">'+wind+'</span></div>',
    '<div class="rc"><span class="rl">Видимость</span><span class="rv lcd">'+vis+'</span></div>',
    '<div class="rc am"><span class="rl">Температура</span><span class="rv lcd">'+temp+'</span></div>',
    '<div class="rc"><span class="rl">Точка росы</span><span class="rv lcd">'+dew+'</span></div>',
    '<div class="rc gr"><span class="rl">QNH</span><span class="rv lcd">'+qnh+'</span></div>',
    '<div class="rc"><span class="rl">Облачность</span><span class="rv" style="font-size:13px">'+cloud+'</span></div>',
  ].join('');
}

function renderMetarDecoded(m){
  var el=g('metar-decoded'); if(!el) return;
  var wind='—', vis='—', cloud='—', temp='—', dew='—', qnh='—', cat='—';
  
  if(m.wdir!==undefined) wind=(m.wdir==='VRB'?'ПЕР':m.wdir+'°')+' '+(m.wspd||0)+' уз';
  if(m.visib) vis=m.visib+' м';
  if(m.temp!==undefined) temp=m.temp+'°C';
  if(m.dewp!==undefined) dew=m.dewp+'°C';
  if(m.altim) qnh=Math.round(m.altim*33.8639)+' гПа';
  if(m.clouds && m.clouds.length) cloud=m.clouds.map(function(c){return (c.cover||c.coverage||'')+(c.base||c.bases||'')+'фт';}).join(', ');
  
  // Flight category color
  var catColors={'VFR':'gr','MVFR':'hi','IFR':'am','LIFR':'rd'};
  var fc=m.fltcat||m.flight_category||'—';
  var cc=catColors[fc]||'';
  
  el.innerHTML=[
    '<div class="rc hi"><span class="rl">Ветер</span><span class="rv lcd">'+wind+'</span></div>',
    '<div class="rc"><span class="rl">Видимость</span><span class="rv lcd">'+vis+'</span></div>',
    '<div class="rc am"><span class="rl">Температура</span><span class="rv lcd">'+temp+'</span></div>',
    '<div class="rc"><span class="rl">Точка росы</span><span class="rv lcd">'+dew+'</span></div>',
    '<div class="rc gr"><span class="rl">QNH</span><span class="rv lcd">'+qnh+'</span></div>',
    '<div class="rc"><span class="rl">Облачность</span><span class="rv" style="font-size:13px">'+cloud+'</span></div>',
    '<div class="rc '+cc+'"><span class="rl">Категория</span><span class="rv lcd">'+fc+'</span></div>',
    '<div class="rc"><span class="rl">Время</span><span class="rv" style="font-size:13px">'+(m.obsTime||m.reportTime||'—')+'</span></div>',
  ].join('');
}

function decodeMetarManual(){
  var raw=(g('metar-manual').value||'').trim().toUpperCase();
  if(!raw){ return; }
  var el=g('metar-manual-result'); el.innerHTML='';
  
  // Parse manually
  var parts=raw.split(/\s+/);
  var icao=parts[0]||'—';
  var time=parts[1]||'—';
  
  // Wind: e.g. 23004MPS or 23010KT
  var windMatch=raw.match(/(\d{3}|VRB)(\d{2,3})(G\d{2,3})?(MPS|KT)/);
  var windStr='—';
  if(windMatch){
    var wd=windMatch[1], ws=parseInt(windMatch[2]), wg=windMatch[3]?parseInt(windMatch[3].slice(1)):null;
    var wsKmh=windMatch[4]==='MPS'?Math.round(ws*3.6):Math.round(ws*1.852);
    windStr=(wd==='VRB'?'Перем':wd+'°')+' '+wsKmh+' км/ч'+(wg?' порыв '+(windMatch[4]==='MPS'?Math.round(wg*3.6):Math.round(wg*1.852))+' км/ч':'');
  }
  
  // Visibility
  var visMatch=raw.match(/(\d{4})/); var visStr=visMatch?(parseInt(visMatch[1])+' м'):'—';
  
  // Temp/Dew: e.g. 16/08 or M02/M05
  var tdMatch=raw.match(/(M?\d{2})\/(M?\d{2})/);
  var tStr='—', dStr='—';
  if(tdMatch){
    tStr=(tdMatch[1].startsWith('M')?'-':'')+parseInt(tdMatch[1].replace('M',''))+'°C';
    dStr=(tdMatch[2].startsWith('M')?'-':'')+parseInt(tdMatch[2].replace('M',''))+'°C';
  }
  
  // QNH: Q followed by 4 digits
  var qMatch=raw.match(/Q(\d{4})/); var qStr=qMatch?(qMatch[1]+' гПа'):'—';
  
  // Clouds
  var clouds=[]; var cRe=/(FEW|SCT|BKN|OVC)(\d{3})/g; var cm;
  while((cm=cRe.exec(raw))!==null){ clouds.push({'FEW':'НЕМНОГО','SCT':'РАССЕЯН','BKN':'ЗНАЧИТ','OVC':'СПЛОШНАЯ'}[cm[1]]+' '+parseInt(cm[2])*100+'фт'); }
  
  el.innerHTML=[
    '<div class="rc"><span class="rl">Аэродром</span><span class="rv lcd">'+icao+'</span></div>',
    '<div class="rc hi"><span class="rl">Ветер</span><span class="rv lcd" style="font-size:14px">'+windStr+'</span></div>',
    '<div class="rc"><span class="rl">Видимость</span><span class="rv lcd">'+visStr+'</span></div>',
    '<div class="rc am"><span class="rl">Темп / Роса</span><span class="rv lcd" style="font-size:14px">'+tStr+' / '+dStr+'</span></div>',
    '<div class="rc gr"><span class="rl">QNH</span><span class="rv lcd">'+qStr+'</span></div>',
    '<div class="rc"><span class="rl">Облачность</span><span class="rv" style="font-size:12px">'+(clouds.length?clouds.join('<br>'):'ЯСНО')+'</span></div>',
  ].join('');
}

