// Полный калькулятор времени
var tcOp = 'add';
var tcAddDir = 1;

function setTCop(op){ tcOp=op; calcTC(); }
function setTCaddDir(d){ tcAddDir=d; calcTCadd(); }

function updateTCOffset(){ /* будет обновлено в тике */ }

function tcParseHMS(str){
  var p=(str||'').split(':');
  return parseInt(p[0]||0)*3600 + parseInt(p[1]||0)*60 + parseInt(p[2]||0);
}
function tcFmtHMS(sec){
  var neg=''; if(sec<0){neg='-';sec=Math.abs(sec);}
  var h=Math.floor(sec/3600)%24, m=Math.floor((sec%3600)/60), s=sec%60;
  return neg+(h<10?'0':'')+h+':'+(m<10?'0':'')+m+':'+(s<10?'0':'')+s;
}
function tcFmtHM(sec){
  var neg=''; if(sec<0){neg='-';sec=Math.abs(sec);}
  var h=Math.floor(sec/3600), m=Math.floor((sec%3600)/60);
  return neg+(h<10?'0':'')+h+':'+(m<10?'0':'')+m;
}

function calcTC(){
  var t1=tcParseHMS(g('tc-t1').value);
  var t2=tcParseHMS(g('tc-t2').value);
  var res, label;
  if(tcOp==='add'){ res=t1+t2; label='Сложение'; }
  else if(tcOp==='sub'){ res=t1-t2; label='Вычитание'; }
  else { res=Math.abs(t1-t2); label='Разница'; }
  g('tc-res').innerText = tcFmtHMS(res);
  g('tc-resmin').innerText = Math.floor(Math.abs(res)/60)+' мин';
  g('tc-ressec').innerText = Math.abs(res)+' с';
  g('tc-op-label').innerText = label;
}

function calcUTCconv(){
  var p=(g('tc-utcin').value||'00:00').split(':');
  var h=parseInt(p[0]||0), m=parseInt(p[1]||0);
  var off=parseInt(g('tc-utcoff').value||0);
  var localSec=((h*60+m)*60 + off*3600 + 86400) % 86400;
  var utcSec=((h*60+m)*60 - off*3600 + 86400) % 86400;
  g('tc-localout').innerText = tcFmtHM(localSec);
  g('tc-utcout').innerText = tcFmtHM(utcSec);
}

function calcTCadd(){
  var now=new Date();
  var utcSec=now.getUTCHours()*3600+now.getUTCMinutes()*60+now.getUTCSeconds();
  var add=(parseInt(g('tc-addh').value||0)*3600+parseInt(g('tc-addm').value||0)*60+parseInt(g('tc-adds').value||0))*tcAddDir;
  var res=(utcSec+add+86400)%86400;
  g('tc-addres').innerText=tcFmtHMS(res);
}

function tickTC(){
  var now=new Date();
  var utcH=now.getUTCHours(), utcM=now.getUTCMinutes(), utcS=now.getUTCSeconds();
  var utcStr=(utcH<10?'0':'')+utcH+':'+(utcM<10?'0':'')+utcM+':'+(utcS<10?'0':'')+utcS;
  g('tc-utc').innerText=utcStr;
  var off3=utcH+3; if(off3>=24)off3-=24;
  g('tc-local').innerText=(off3<10?'0':'')+off3+':'+(utcM<10?'0':'')+utcM+':'+(utcS<10?'0':'')+utcS;
  var offC=parseInt(g('tc-offset').value||0);
  var cH=(utcH+offC+24)%24;
  g('tc-custom').innerText=(cH<10?'0':'')+cH+':'+(utcM<10?'0':'')+utcM+':'+(utcS<10?'0':'')+utcS;
}
setInterval(tickTC, 1000);


