var currentAC = 'su25';

function renderACPage(key, pageId) {
  var el = g(pageId);
  if (!el || el.dataset.rendered) return;
  el.dataset.rendered = '1';
  var d = acData[key];
  var photo = acPhotos[key] || '';
  var badgeClass = d.badge === 'mil' ? 'mil' : 'civ';
  var badgeText  = d.badge === 'mil' ? '⚔ ВОЕННЫЙ' : '✈ ГРАЖДАНСКИЙ';
  var rows = d.specs.map(function(s) {
    if(s.sec) return '<div class="ref-section">'+s.sec+'</div>';
    return '<div class="ref-row"><span class="ref-key">'+s.k+'</span><span class="ref-val'+(s.c?' '+s.c:'')+'" >'+s.v+'</span></div>';
  }).join('');
  el.innerHTML =
    '<div class="panel">' +
      '<div class="pb">' +
        '<img class="ref-photo" src="'+photo+'" alt="'+d.name+'" onerror="this.style.display=\'none\';this.nextSibling.style.display=\'flex\'" loading="lazy">' +
        '<div style="display:none;height:160px;background:var(--s2);border-radius:8px;margin-bottom:.7rem;border:1px solid var(--br);align-items:center;justify-content:center;font-family:var(--mono);font-size:11px;color:var(--mu);letter-spacing:2px;">📷 ФОТО НЕДОСТУПНО<br><span style="font-size:9px;margin-top:4px;display:block">Требуется интернет</span></div>' +
        '<div class="ref-title">'+d.name+'</div>' +
        '<div class="ref-role"><span class="ref-badge '+badgeClass+'">'+badgeText+'</span>'+d.nameEn+'</div>' +
        rows +
        '<div class="ref-note">ℹ️ '+d.note+'</div>' +
      '</div>' +
    '</div>';
}


function fixScrollHeight(){ /* replaced by CSS flex layout */ }

window.onload = function(){
  calc(); meteoCalc(); turnCalc(); pnrCalc(); renderHistory();
  tickTC(); calcTC(); calcUTCconv(); calcTCadd();
  calcISA(); calcISApoint(); calcWB(); setWBProfile('su25');
  updateHorizon(parseFloat(g('tn-bank').value||25), 1/Math.cos(25*Math.PI/180));
  fixScrollHeight();
  window.addEventListener('resize', fixScrollHeight);
};


// =================== EFB PRO ADDON ===================
var efbWatchId=null, efbPos=null, efbRoute=[], efbTraffic=[], efbTrafficOn=false;
function efbSetStatus(msg){ var el=g('efb-status'); if(el) el.innerText=msg; }
function efbNum(id, fallback){ var el=g(id); var v=el?parseFloat(el.value):NaN; return isNaN(v)?fallback:v; }
function efbRad(d){ return d*Math.PI/180; }
function efbDeg(r){ return (r*180/Math.PI+360)%360; }
function efbDistKm(a,b,c,d){ var R=6371, dLat=efbRad(c-a), dLon=efbRad(d-b); var x=Math.sin(dLat/2)*Math.sin(dLat/2)+Math.cos(efbRad(a))*Math.cos(efbRad(c))*Math.sin(dLon/2)*Math.sin(dLon/2); return 2*R*Math.atan2(Math.sqrt(x),Math.sqrt(1-x)); }
function efbBrg(a,b,c,d){ var y=Math.sin(efbRad(d-b))*Math.cos(efbRad(c)); var x=Math.cos(efbRad(a))*Math.sin(efbRad(c))-Math.sin(efbRad(a))*Math.cos(efbRad(c))*Math.cos(efbRad(d-b)); return efbDeg(Math.atan2(y,x)); }
function efbFmtTime(h){ if(!isFinite(h)||h<0) return '—'; var m=Math.round(h*60); return Math.floor(m/60)+'ч '+String(m%60).padStart(2,'0')+'м'; }
function efbInit(){ efbLoadMission(); efbRenderRoute(); efbCalcFuel(); efbDrawTraffic(); efbSyncHUD(); }
function efbGeoHelp(err){
  var secure = window.isSecureContext || location.protocol==='https:' || location.hostname==='localhost' || location.hostname==='127.0.0.1';
  if(err && err.code===1) return '⚠ GPS: доступ запрещён. Нажмите на замок/настройки сайта → Геолокация → Разрешить, затем перезагрузите страницу.' + (secure?'':' Важно: откройте приложение через HTTPS или localhost; из обычного file:// GPS часто блокируется.');
  if(err && err.code===2) return '⚠ GPS: координаты недоступны. Включите геолокацию на телефоне и выйдите на открытое место.';
  if(err && err.code===3) return '⚠ GPS: таймаут. Попробуйте ещё раз или включите режим высокой точности.';
  return secure ? '⚠ GPS: ошибка геолокации.' : '⚠ GPS требует HTTPS/localhost. Для проверки нажмите 🧪 GPS-симулятор.';
}
function efbStartGPS(){
  if(!('geolocation' in navigator)){ efbSetStatus('⚠ Геолокация не поддерживается этим браузером'); return; }
  if(!(window.isSecureContext || location.protocol==='https:' || location.hostname==='localhost' || location.hostname==='127.0.0.1')){
    efbSetStatus('⚠ GPS заблокирован браузером: откройте приложение через HTTPS/localhost. Для проверки нажмите 🧪 GPS-симулятор.');
  } else efbSetStatus('📡 GPS запускается... подтвердите разрешение браузера');
  if(efbWatchId!==null) navigator.geolocation.clearWatch(efbWatchId);
  efbWatchId=navigator.geolocation.watchPosition(efbOnPos,function(err){ efbSetStatus(efbGeoHelp(err)); },{enableHighAccuracy:true,maximumAge:1000,timeout:15000});
}
function efbUseSimGPS(){
  efbPos={lat:51.53172,lon:43.30164,alt:180,spd:140,hdg:87,acc:5,ts:Date.now()};
  localStorage.setItem('efb-last-pos', JSON.stringify(efbPos));
  efbSyncHUD(); efbUpdateMapMarker(); efbSetStatus('🧪 GPS-симулятор включён: тестовая позиция загружена. Реальный GPS требует разрешения и HTTPS/localhost.');
}
function efbStopGPS(){ if(efbWatchId!==null){ navigator.geolocation.clearWatch(efbWatchId); efbWatchId=null; } efbSetStatus('GPS остановлен'); }
function efbOnPos(pos){ efbPos={lat:pos.coords.latitude, lon:pos.coords.longitude, alt:pos.coords.altitude, spd:pos.coords.speed, hdg:pos.coords.heading, acc:pos.coords.accuracy, ts:Date.now()}; localStorage.setItem('efb-last-pos', JSON.stringify(efbPos)); efbSyncHUD(); efbUpdateMapMarker(); }
function efbSyncHUD(){ if(!efbPos){ try{ efbPos=JSON.parse(localStorage.getItem('efb-last-pos')||'null'); }catch(e){} } var next=efbRoute[0]||null, gs=0, heading='---'; if(efbPos){ gs=efbPos.spd?efbPos.spd*3.6:0; heading=isFinite(efbPos.hdg)?Math.round(efbPos.hdg):'---'; if(g('efb-coord')) g('efb-coord').innerText=efbPos.lat.toFixed(5)+', '+efbPos.lon.toFixed(5)+' · ±'+Math.round(efbPos.acc||0)+'м'; if(g('efb-alt')) g('efb-alt').innerText=isFinite(efbPos.alt)?Math.round(efbPos.alt):'—'; if(g('efb-gs')) g('efb-gs').innerText=gs?Math.round(gs):'—'; } if(g('efb-hdg')) g('efb-hdg').innerText=heading+'°'; if(next && efbPos){ var d=efbDistKm(efbPos.lat,efbPos.lon,next.lat,next.lon), b=efbBrg(efbPos.lat,efbPos.lon,next.lat,next.lon); g('efb-next').innerText=next.name; g('efb-brg').innerText=Math.round(b)+'°'; g('efb-dist').innerText=d.toFixed(1); g('efb-eta').innerText=gs>5?efbFmtTime(d/gs):'—'; if(d<1 && navigator.vibrate) navigator.vibrate([120,80,120]); } else { ['efb-next','efb-brg','efb-dist','efb-eta'].forEach(function(id){ var el=g(id); if(el) el.innerText='—'; }); } efbCalcFuel(); }
function efbAddWP(){ var name=(g('efb-wp-name').value||('WP'+(efbRoute.length+1))).trim(); var lat=efbNum('efb-wp-lat',NaN), lon=efbNum('efb-wp-lon',NaN); if(!isFinite(lat)||!isFinite(lon)){efbSetStatus('⚠ Неверные координаты');return;} efbRoute.push({name:name,lat:lat,lon:lon}); g('efb-wp-name').value='WP'+(efbRoute.length+1); efbSaveMission(); efbRenderRoute(); }
function efbAddCurrentWP(){ if(!efbPos){ efbSetStatus('⚠ Сначала запустите GPS'); return; } g('efb-wp-lat').value=efbPos.lat.toFixed(6); g('efb-wp-lon').value=efbPos.lon.toFixed(6); g('efb-wp-name').value='GPS '+(efbRoute.length+1); efbAddWP(); }
function efbDeleteWP(i){ efbRoute.splice(i,1); efbSaveMission(); efbRenderRoute(); }
function efbClearMission(){ efbRoute=[]; efbSaveMission(); efbRenderRoute(); efbSetStatus('Маршрут очищен'); }
function efbRouteTotal(){ var total=0, prev=efbPos; for(var i=0;i<efbRoute.length;i++){ if(prev) total+=efbDistKm(prev.lat,prev.lon,efbRoute[i].lat,efbRoute[i].lon); prev=efbRoute[i]; } return total; }
function efbRenderRoute(){ var body=g('efb-wp-body'); if(!body) return; body.innerHTML=''; var prev=efbPos; efbRoute.forEach(function(w,i){ var brg='—', dist='—'; if(prev){ brg=Math.round(efbBrg(prev.lat,prev.lon,w.lat,w.lon))+'°'; dist=efbDistKm(prev.lat,prev.lon,w.lat,w.lon).toFixed(1); } var tr=document.createElement('tr'); tr.innerHTML='<td>'+(i+1)+'</td><td>'+w.name+'</td><td>'+w.lat.toFixed(5)+'</td><td>'+w.lon.toFixed(5)+'</td><td>'+brg+'</td><td>'+dist+'</td><td><span class="del-row" onclick="efbDeleteWP('+i+')">×</span></td>'; body.appendChild(tr); prev=w; }); efbCalcFuel(); efbSyncHUD(); }
function efbSaveMission(){ localStorage.setItem('efb-route-v1',JSON.stringify(efbRoute)); }
function efbLoadMission(){ try{ efbRoute=JSON.parse(localStorage.getItem('efb-route-v1')||'[]')||[]; }catch(e){ efbRoute=[]; } }
function efbLoadRouteFromTable(){ var rows=document.querySelectorAll('#route-body tr'); var added=0; rows.forEach(function(row){ var inp=row.querySelector('td:first-child input'); if(!inp) return; var m=(inp.value||'').match(/GPS\s*([-\d.]+)[,\s]+([-\d.]+)/i); if(m){ efbRoute.push({name:'RT '+(added+1),lat:parseFloat(m[1]),lon:parseFloat(m[2])}); added++; } }); efbSaveMission(); efbRenderRoute(); efbSetStatus(added?('Импортировано точек: '+added):'В таблице маршрута GPS-точек не найдено'); }
function efbCalcFuel(){ var flow=efbNum('efb-fuel-flow',1200), onboard=efbNum('efb-fuel-onboard',2400), reserve=efbNum('efb-fuel-reserve',400); var speed=efbPos&&efbPos.spd?efbPos.spd*3.6:efbNum('vias',550); var dist=efbRouteTotal()||efbNum('dist',0); var hours=speed>1?dist/speed:0; var need=hours*flow, land=onboard-need, bingo=(onboard-reserve)/flow; if(g('efb-fuel-need')) g('efb-fuel-need').innerText=Math.round(need)+' кг'; if(g('efb-fuel-land')) g('efb-fuel-land').innerText=Math.round(land)+' кг'; if(g('efb-fuel-end')) g('efb-fuel-end').innerText=efbFmtTime(onboard/flow); if(g('efb-fuel-bingo')) g('efb-fuel-bingo').innerText=efbFmtTime(bingo); var lf=g('efb-fuel-land'); if(lf){ var rc=lf.closest('.rc'); if(rc) rc.classList.toggle('danger-warn',land<reserve); } }
function efbVoiceBrief(){ var text='Брифинг миссии. Путевых точек '+efbRoute.length+'. Остаток топлива на посадке '+(g('efb-fuel-land')?g('efb-fuel-land').innerText:'unknown')+'.'; if('speechSynthesis' in window){ var u=new SpeechSynthesisUtterance(text); u.lang='ru-RU'; speechSynthesis.cancel(); speechSynthesis.speak(u); efbSetStatus('🎙 Голосовой брифинг воспроизводится'); } else efbSetStatus('⚠ Голос не поддерживается'); }
function efbExportMission(){ var data={created:new Date().toISOString(), route:efbRoute, fuel:{onboard:g('efb-fuel-onboard').value,flow:g('efb-fuel-flow').value,reserve:g('efb-fuel-reserve').value}, note:'Экспорт миссии AvisCalc: маршрут и топливо'}; var blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'}); var a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='aviscalc_mission_ru.json'; a.click(); setTimeout(function(){URL.revokeObjectURL(a.href)},1000); efbSetStatus('💾 Миссия экспортирована в JSON'); }
function efbToggleTraffic(){ efbTrafficOn=!efbTrafficOn; if(efbTrafficOn && !efbTraffic.length){ for(var i=0;i<4;i++) efbAddTraffic(true); } efbDrawTraffic(); efbSetStatus(efbTrafficOn?'Учебный трафик включён':'Учебный трафик выключен'); }
function efbAddTraffic(silent){ var brg=Math.random()*360, d=10+Math.random()*90, alt=Math.round((500+Math.random()*7000)/100)*100; efbTraffic.push({brg:brg,dist:d,alt:alt,cs:'T'+String(100+efbTraffic.length)}); efbTrafficOn=true; efbDrawTraffic(); if(!silent) efbSetStatus('Добавлена учебная цель'); }
function efbDrawTraffic(){ var layer=g('efb-traffic-layer'); if(!layer) return; layer.innerHTML=''; if(!efbTrafficOn) return; efbTraffic.forEach(function(t){ var r=Math.min(115,t.dist/100*115), a=efbRad(t.brg-90), x=130+Math.cos(a)*r, y=130+Math.sin(a)*r; var color=t.dist<20?'var(--rd)':(t.dist<45?'var(--am)':'var(--gr)'); layer.innerHTML += '<g><circle cx="'+x.toFixed(1)+'" cy="'+y.toFixed(1)+'" r="4" fill="'+color+'"/><text x="'+(x+6).toFixed(1)+'" y="'+(y-6).toFixed(1)+'" fill="'+color+'" font-size="8" font-family="monospace">'+t.cs+' '+t.alt+'</text></g>'; }); }
function efbDim(){ var d=g('efb-dim'); if(d) d.style.display=(d.style.display==='none'||!d.style.display)?'block':'none'; }
function efbUpdateMapMarker(){ if(typeof L==='undefined' || !_map || !efbPos) return; if(!_gpsMarker){ _gpsMarker=L.circleMarker([efbPos.lat,efbPos.lon],{radius:8,color:'#00c8ff',fillColor:'#00c8ff',fillOpacity:1,weight:2}).addTo(_map); } else _gpsMarker.setLatLng([efbPos.lat,efbPos.lon]); }

