var deferredPrompt = null;
window.addEventListener('beforeinstallprompt', function(e){
  e.preventDefault();
  deferredPrompt = e;
  showInstallBanner();
});

function showInstallBanner(){
  var banner = g('pwa-banner');
  if(banner) banner.style.display='flex';
}

function installPWA(){
  if(deferredPrompt){
    deferredPrompt.prompt();
    deferredPrompt.userChoice.then(function(r){
      deferredPrompt = null;
      var banner = g('pwa-banner');
      if(banner) banner.style.display='none';
    });
  }
}

function dismissPWA(){
  var banner = g('pwa-banner');
  if(banner) banner.style.display='none';
}

// ===== GEOLOCATION =====

// Найти ближайший аэродром по координатам (использует API open-aip или fallback-список)
function geoFindNearestAirport(){
  var statusEl = g('geo-status-metar');
  if(!('geolocation' in navigator)){
    statusEl.style.display='block';
    statusEl.style.color='var(--rd)';
    statusEl.innerText='⚠ Геолокация не поддерживается браузером';
    return;
  }
  statusEl.style.display='block';
  statusEl.style.color='var(--mu)';
  statusEl.innerText='📡 Определяем координаты...';

  navigator.geolocation.getCurrentPosition(function(pos){
    var lat = pos.coords.latitude;
    var lon = pos.coords.longitude;
    statusEl.innerText = '📍 ' + lat.toFixed(4) + '°, ' + lon.toFixed(4) + '° — ищем аэродром...';

    // База ближайших аэродромов (расширенный список для России/СНГ)
    var airports = [
      {icao:'XWSW', name:'Балашов',   lat:51.5317, lon:43.3016},
      {icao:'UWSS', name:'Саратов',    lat:51.5650, lon:46.0467},
      {icao:'UWWW', name:'Самара',     lat:53.5050, lon:50.1642},
      {icao:'UUDD', name:'Домодедово', lat:55.4088, lon:37.9063},
      {icao:'UUEE', name:'Шереметьево',lat:55.9726, lon:37.4146},
      {icao:'ULLI', name:'Пулково',    lat:59.8003, lon:30.2625},
      {icao:'URSS', name:'Сочи',       lat:43.4495, lon:39.9456},
      {icao:'UNNT', name:'Новосибирск',lat:55.0126, lon:82.6507},
      {icao:'USSS', name:'Екатеринбург',lat:56.7431, lon:60.8027},
      {icao:'ULLI', name:'Пулково',    lat:59.8003, lon:30.2625},
      {icao:'UWKD', name:'Казань',     lat:55.6063, lon:49.2787},
      {icao:'UHWW', name:'Владивосток',lat:43.3990, lon:132.1479},
      {icao:'UKBB', name:'Борисполь',  lat:50.3450, lon:30.8947},
      {icao:'EVRA', name:'Рига',       lat:56.9236, lon:23.9711},
      {icao:'EFHK', name:'Хельсинки', lat:60.3172, lon:24.9633},
      {icao:'EPWA', name:'Варшава',    lat:52.1657, lon:20.9671},
      {icao:'LOWI', name:'Инсбрук',   lat:47.2602, lon:11.3440},
      {icao:'EDDF', name:'Франкфурт', lat:50.0264, lon:8.5431},
    ];

    // Формула расстояния по Haversine
    function haverDist(lat1,lon1,lat2,lon2){
      var R=6371, dLat=(lat2-lat1)*Math.PI/180, dLon=(lon2-lon1)*Math.PI/180;
      var a=Math.sin(dLat/2)*Math.sin(dLat/2)+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)*Math.sin(dLon/2);
      return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
    }

    var best=null, bestDist=Infinity;
    airports.forEach(function(a){
      var d=haverDist(lat,lon,a.lat,a.lon);
      if(d<bestDist){bestDist=d;best=a;}
    });

    if(best){
      g('metar-icao').value = best.icao;
      statusEl.style.color='var(--gr)';
      statusEl.innerText = '✅ Ближайший: ' + best.name + ' (' + best.icao + ') — ' + Math.round(bestDist) + ' км';
    } else {
      statusEl.style.color='var(--rd)';
      statusEl.innerText = '❌ Аэродром не найден в базе';
    }
  }, function(err){
    statusEl.style.display='block';
    statusEl.style.color='var(--rd)';
    var msgs = {1:'Доступ к геолокации запрещён',2:'Координаты недоступны',3:'Превышено время ожидания'};
    statusEl.innerText = '⚠ ' + (msgs[err.code]||'Ошибка геолокации');
  }, {timeout:10000, enableHighAccuracy:false});
}

// Добавить GPS-точку как ППМ в маршрут
function geoAddCurrentPos(){
  var statusEl = g('geo-status-route');
  if(!('geolocation' in navigator)){
    statusEl.style.display='block';
    statusEl.style.color='var(--rd)';
    statusEl.innerText='⚠ Геолокация не поддерживается браузером';
    return;
  }
  statusEl.style.display='block';
  statusEl.style.color='var(--mu)';
  statusEl.innerText='📡 Определяем координаты...';

  navigator.geolocation.getCurrentPosition(function(pos){
    var lat = pos.coords.latitude.toFixed(5);
    var lon = pos.coords.longitude.toFixed(5);
    var acc = Math.round(pos.coords.accuracy);

    // Добавить строку ППМ с координатами
    addRouteRow();
    var rows = document.querySelectorAll('#route-body tr');
    var lastRow = rows[rows.length-1];
    if(lastRow){
      var nameInput = lastRow.querySelector('td:first-child input');
      if(nameInput) nameInput.value = 'GPS ' + lat + ',' + lon;
    }

    statusEl.style.color='var(--gr)';
    statusEl.innerText = '✅ ' + lat + '°, ' + lon + '° (±' + acc + ' м) — добавлено в маршрут';
    setTimeout(function(){ statusEl.style.display='none'; }, 5000);
  }, function(err){
    statusEl.style.color='var(--rd)';
    var msgs = {1:'Доступ к геолокации запрещён',2:'Координаты недоступны',3:'Превышено время ожидания'};
    statusEl.innerText = '⚠ ' + (msgs[err.code]||'Ошибка геолокации');
  }, {timeout:10000, enableHighAccuracy:true});
}

