var _map = null, _routeLayer = null, _airportLayer = null, _gpsMarker = null, _gpsCircle = null;

var _tiles = {
  osm: {
    url: 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',
    attr: '© OpenStreetMap'
  },
  topo: {
    url: 'https://{s}.tile.opentopomap.org/{z}/{x}/{y}.png',
    attr: '© OpenTopoMap'
  },
  sat: {
    url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',
    attr: '© Esri'
  }
};
var _currentTileLayer = null;

function initMap() {
  if (_map) return;
  if (typeof L === 'undefined') {
    mapStatus('Карта недоступна: библиотека Leaflet не загрузилась. Проверьте интернет или локальный файл Leaflet.');
    return;
  }
  _map = L.map('map-container', { zoomControl: true, attributionControl: false }).setView([55.0, 40.0], 5);
  _currentTileLayer = L.tileLayer(_tiles.osm.url, { maxZoom: 18 }).addTo(_map);
  _routeLayer = L.layerGroup().addTo(_map);
  _airportLayer = L.layerGroup().addTo(_map);
  mapStatus('Карта загружена · Нажмите 📍 для определения места');
  // Show airports by default
  mapShowAirports();
}

function mapStatus(msg) {
  var el = g('map-status');
  if (el) el.innerText = msg;
}

function mapChangeTile(key) {
  if (!_map) return;
  if (_currentTileLayer) _map.removeLayer(_currentTileLayer);
  _currentTileLayer = L.tileLayer(_tiles[key].url, { maxZoom: 18 }).addTo(_map);
}

function mapGoGPS() {
  if (!_map) initMap();
  if (!('geolocation' in navigator)) { mapStatus('⚠ Геолокация не поддерживается'); return; }
  mapStatus('📡 Определяем координаты...');
  navigator.geolocation.getCurrentPosition(function(pos) {
    var lat = pos.coords.latitude, lon = pos.coords.longitude;
    var acc = Math.round(pos.coords.accuracy);
    if (_gpsMarker) _map.removeLayer(_gpsMarker);
    if (_gpsCircle) _map.removeLayer(_gpsCircle);
    _gpsCircle = L.circle([lat, lon], { radius: acc, color: '#00c8ff', fillColor: '#00c8ff', fillOpacity: 0.1, weight: 1 }).addTo(_map);
    _gpsMarker = L.circleMarker([lat, lon], { radius: 8, color: '#00c8ff', fillColor: '#00c8ff', fillOpacity: 1, weight: 2 })
      .bindPopup('<b style="font-family:monospace">📍 Вы здесь</b><br><span style="font-family:monospace;font-size:11px">' + lat.toFixed(5) + ', ' + lon.toFixed(5) + '<br>Точность: ±' + acc + ' м</span>')
      .addTo(_map).openPopup();
    _map.setView([lat, lon], 10);
    mapStatus('📍 ' + lat.toFixed(4) + '°, ' + lon.toFixed(4) + '° · ±' + acc + ' м');
  }, function(err) {
    mapStatus(efbGeoHelp ? efbGeoHelp(err) : '⚠ Ошибка геолокации');
  }, { timeout: 10000, enableHighAccuracy: true });
}

function mapShowRoute() {
  if (!_map) initMap();
  _routeLayer.clearLayers();
  var rows = document.querySelectorAll('#route-body tr');
  if (!rows.length) { mapStatus('⚠ Маршрут пуст — добавьте ППМ во вкладке Маршрут'); return; }
  var points = [], count = 0;
  rows.forEach(function(row) {
    var nameCell = row.querySelector('td:first-child input');
    if (!nameCell) return;
    var val = nameCell.value || '';
    // Parse GPS coords from name like "GPS 55.12345,40.12345"
    var m = val.match(/GPS\s*([-\d.]+)[,\s]+([-\d.]+)/i);
    if (m) {
      var lat = parseFloat(m[1]), lon = parseFloat(m[2]);
      points.push([lat, lon]);
      L.circleMarker([lat, lon], { radius: 7, color: '#00e5a0', fillColor: '#00e5a0', fillOpacity: 1 })
        .bindPopup('<span style="font-family:monospace;font-size:12px">📍 ' + val + '</span>')
        .addTo(_routeLayer);
      count++;
    }
  });
  if (points.length > 1) {
    L.polyline(points, { color: '#00c8ff', weight: 2, dashArray: '6,4', opacity: 0.85 }).addTo(_routeLayer);
    _map.fitBounds(L.polyline(points).getBounds(), { padding: [30, 30] });
  } else if (points.length === 1) {
    _map.setView(points[0], 10);
  }
  mapStatus('✈️ Показано GPS-точек маршрута: ' + count + (count === 0 ? ' · Добавьте GPS-точки во вкладке Маршрут' : ''));
}

