// Балашов центр: 51.5317, 43.3016
// Карта покрывает ~115км по горизонтали и ~80км по вертикали (оценка по масштабу)
// Размер изображения 3390x2363, соотношение сторон 1.435
// Оверлей bounds: центр Балашова +/- ~57км по долготе, ~40км по широте
// 1° широты ≈ 111 км => 0.36°
// 1° долготы ≈ 68 км => 0.84°
var _zoneBounds = [
  [51.5317 - 0.57, 43.3016 - 1.24],
  [51.5317 + 0.57, 43.3016 + 1.24]
];

var _zoneOverlay = null;
var _zoneActive = 0;

function mapToggleZone(mpr) {
  if (!_map) initMap();
  if (_zoneActive === mpr) {
    mapClearZone();
    return;
  }
  mapClearZone();
  _zoneActive = mpr;
  var opacity = parseInt(document.getElementById('zone-opacity').value) / 100;
  _zoneOverlay = L.imageOverlay(_zoneImages[mpr], _zoneBounds, {
    opacity: opacity,
    interactive: false
  }).addTo(_map);
  _map.fitBounds(_zoneBounds);
  var bar = document.getElementById('zone-opacity-bar');
  bar.style.display = 'flex';
  document.getElementById('zone-active-label').innerText = 'Зона МПР ' + mpr + '°';
  mapStatus('📋 Зона МПР ' + mpr + '° включена · используйте слайдер для прозрачности');
  // Highlight active button
  ['168','348'].forEach(function(n) {
    var btns = document.querySelectorAll('.sbtn');
    // not ideal but functional
  });
}

function mapClearZone() {
  if (_zoneOverlay) { _map.removeLayer(_zoneOverlay); _zoneOverlay = null; }
  _zoneActive = 0;
  document.getElementById('zone-opacity-bar').style.display = 'none';
  mapStatus('Оверлей зоны скрыт');
}

function mapSetZoneOpacity(val) {
  document.getElementById('zone-opacity-val').innerText = val + '%';
  if (_zoneOverlay) _zoneOverlay.setOpacity(parseInt(val) / 100);
}

// =================== ZONE VIEWER ===================
var _zvActive = 0;
function zonesViewShow(mpr) {
  _zvActive = mpr;
  var container = document.getElementById('zv-container');
  var zoom = document.getElementById('zv-zoom').value;
  container.innerHTML = '<img src="' + _zoneImages[mpr] + '" style="max-width:' + zoom + '%;height:auto;display:block" />';
  // Highlight buttons
  document.getElementById('zv-btn-168').style.background = (mpr===168) ? 'var(--ac2)' : '';
  document.getElementById('zv-btn-168').style.color = (mpr===168) ? '#fff' : '';
  document.getElementById('zv-btn-348').style.background = (mpr===348) ? 'var(--ac2)' : '';
  document.getElementById('zv-btn-348').style.color = (mpr===348) ? '#fff' : '';
}

function zonesViewZoom(val) {
  if (!_zvActive) return;
  var img = document.querySelector('#zv-container img');
  if (img) img.style.maxWidth = val + '%';
}

