(function(){
  function q(s){return document.querySelector(s)}
  function qa(s){return Array.prototype.slice.call(document.querySelectorAll(s))}
  function pad(n){return String(n).padStart(2,'0')}
  window.avisSetProfile=function(name,btn){
    qa('.avis-profile').forEach(function(b){b.classList.remove('active')});
    if(btn) btn.classList.add('active');
    var p=q('#avis-profile-pill'); if(p) p.textContent='ВС: '+name;
    try{localStorage.setItem('avis_os_profile',name)}catch(e){}
  };
  window.avisTheme=function(name){
    document.body.classList.remove('avis-theme-nvg','avis-theme-amber','avis-theme-tactical');
    if(name!=='civil') document.body.classList.add('avis-theme-'+name);
    var d=q('#avis-dash-theme'); if(d) d.textContent=name.toUpperCase();
    try{localStorage.setItem('avis_os_theme',name)}catch(e){}
  };
  function updateClock(){
    var d=new Date();
    var t='UTC '+pad(d.getUTCHours())+':'+pad(d.getUTCMinutes());
    var el=q('#avis-time-pill'); if(el) el.textContent=t;
  }
  function updateDock(tab){
    qa('.avis-dock-btn').forEach(function(b){b.classList.remove('active')});
    qa('.avis-dock-btn').forEach(function(b){ if(b.getAttribute('onclick') && b.getAttribute('onclick').indexOf("'"+tab+"'")>-1) b.classList.add('active'); });
  }
  var prev=window.showTab;
  if(typeof prev==='function'){
    window.showTab=function(t){ prev(t); updateDock(t); };
  }
  function gpsStatus(txt,cls){
    var pill=q('#avis-gps-pill'), dash=q('#avis-dash-gps'), sub=q('#avis-dash-gps-sub');
    if(pill){pill.className='avis-pill '+(cls||''); pill.textContent='GPS: '+txt;}
    if(dash) dash.textContent=txt.split(' ')[0].toUpperCase();
    if(sub) sub.textContent=txt;
  }
  function tryGPS(){
    if(!navigator.geolocation){gpsStatus('нет API','rd');return;}
    navigator.geolocation.getCurrentPosition(function(pos){
      gpsStatus('активен','ok');
      var h=pos.coords.heading; if(h==null || isNaN(h)) h=0;
      var c=q('#avis-compass'); if(c) c.textContent='HDG '+String(Math.round(h)).padStart(3,'0')+' · GPS LOCK';
    },function(err){
      var msg=err && err.code===1 ? 'доступ запрещён' : 'ожидание';
      gpsStatus(msg, err && err.code===1?'rd':'warn');
    },{enableHighAccuracy:true,maximumAge:15000,timeout:3500});
  }
  document.addEventListener('DOMContentLoaded',function(){
    document.body.classList.add('avis-os-ready');
    updateClock(); setInterval(updateClock,30000);
    setTimeout(function(){var b=q('#avis-boot'); if(b) b.classList.remove('on')},2400);
    try{var th=localStorage.getItem('avis_os_theme'); if(th) avisTheme(th);}catch(e){}
    try{var pr=localStorage.getItem('avis_os_profile'); if(pr){var p=q('#avis-profile-pill'); if(p)p.textContent='ВС: '+pr;}}catch(e){}
    tryGPS();
  });
})();

