(function(){
  const nav = [
    ["avisos","▣","Панель","Главный экран"],
    ["calc","✈","Расчёт","Ветер / курс"],
    ["route","⌖","Маршрут","Навигация"],
    ["mag","◆","Магнит.","Курс / склон."],
    ["meteo","☁","Метео","Погода"],
    ["fuel","▰","Топливо","Запас / вираж"],
    ["conv","⇄","Конвертер","Единицы"],
    ["timer","◷","Таймер","Отсчёт"],
    ["timecalc","◴","Время","План"],
    ["metar","☈","METAR","Сводки"],
    ["wb","⚖","W&B","Центровка"],
    ["isa","△","ISA","Атмосфера"],
    ["hist","☷","История","Расчёты"],
    ["map","◎","Карта","GPS"],
    ["efb","▤","EFB","Pro"],
    ["zones","▥","Зоны","Справочник"],
    ["aircraft","✈","Самолёты","Справочник ВС"]
  ];

  const ruMap = new Map([
    ["AVIS OS","АВИС ОС"],["TACTICAL SUITE","РЕТРО LCD"],["MISSION CONTROL","ЦЕНТР ПОЛЁТА"],
    ["ACTIVE PROFILE","ПРОФИЛЬ"],["QUICK MODULES","МОДУЛИ"],["FLIGHT DATA","ПОЛЁТНЫЕ ДАННЫЕ"],
    ["WIND","ВЕТЕР"],["FUEL","ТОПЛИВО"],["TIME","ВРЕМЯ"],["ROUTE","МАРШРУТ"],["CONVERTER","КОНВЕРТЕР"],
    ["HISTORY","ИСТОРИЯ"],["PROFILE","ПРОФИЛЬ"],["SETTINGS","НАСТРОЙКИ"],["RESULTS","РЕЗУЛЬТАТЫ"],
    ["CALCULATE","РАССЧИТАТЬ"],["RESET","СБРОС"],["HEADWIND","ПОПУТНЫЙ"],["CROSSWIND","БОКОВОЙ"],
    ["DRIFT ANGLE","УГОЛ СНОСА"],["CORR. HDG","ИСПР. КУРС"],["GROUND SPEED","ПУТЕВАЯ"],
    ["DIR","НАПР."],["SPD","СКОР."],["GPS READY","GPS ГОТОВ"],["GPS OK","GPS ГОТОВ"],
    ["READY","ГОТОВ"],["STATUS","СТАТУС"],["SYNCED","СИНХР."],["MODE","РЕЖИМ"],["CALC","РАСЧ."]
  ]);

  function buildShell(){
    if(document.querySelector(".retro-shell")) return;

    document.body.classList.add("retro-true");

    const scroll = document.querySelector(".scroll");
    if(!scroll) return;

    const shell = document.createElement("div");
    shell.className = "retro-shell";
    shell.innerHTML = `
      <i class="retro-screw-bl"></i>
      <i class="retro-screw-br"></i>

      <section class="retro-top">
        <div class="retro-brand">
          <div class="retro-brand-kicker">ШТУРМАНСКИЙ КАЛЬКУЛЯТОР · РЕТРО-АВИОНИКА</div>
          <div class="retro-brand-title">AVIS CALC</div>
          <div class="retro-brand-sub">LCD PANEL / РУССКАЯ ВЕРСИЯ / ФУНКЦИОНАЛ СОХРАНЁН</div>
        </div>
        <div class="retro-status-cluster">
          <div class="retro-lamp">GPS<b id="retro-gps">ГОТОВ</b></div>
          <div class="retro-lamp">UTC<b id="retro-utc">--:--</b></div>
          <div class="retro-lamp">ВС<b id="retro-ac">СУ-25</b></div>
          <div class="retro-lamp">РЕЖИМ<b>РАСЧ.</b></div>
        </div>
      </section>

      <aside class="retro-side">
        <div class="retro-side-title">ПАНЕЛЬ ВЫБОРА</div>
        <nav class="retro-nav"></nav>
        <div class="retro-side-footer">
          <b>AVIS LCD</b><br>
          Аппаратная оболочка активна<br>
          Формулы и расчёты: оригинальные
        </div>
      </aside>

      <main class="retro-screen-wrap"></main>
    `;

    document.body.appendChild(shell);
    shell.querySelector(".retro-screen-wrap").appendChild(scroll);

    const navBox = shell.querySelector(".retro-nav");
    for(const [id,ico,title,sub] of nav){
      const btn = document.createElement("button");
      btn.className = "retro-nav-btn";
      btn.dataset.tab = id;
      btn.innerHTML = `<span class="ico">${ico}</span><span><b>${title}</b><small>${sub}</small></span>`;
      btn.addEventListener("click", () => {
        if(typeof window.showTab === "function") window.showTab(id);
        else fallbackShowTab(id);
        setActive(id);
      });
      navBox.appendChild(btn);
    }

    const current = document.querySelector(".page.active")?.id?.replace(/^tab-/,"") || "avisos";
    setActive(current);
    syncClock();
    setInterval(syncClock, 1000);
    translateVisible(document.body);
    observeTranslations();
  }

  function fallbackShowTab(id){
    document.querySelectorAll(".page").forEach(p=>p.classList.remove("active"));
    document.getElementById("tab-"+id)?.classList.add("active");
  }

  function setActive(id){
    document.querySelectorAll(".retro-nav-btn").forEach(b=>b.classList.toggle("active", b.dataset.tab === id));
    const active = document.querySelector(`.retro-nav-btn[data-tab="${id}"]`);
    if(active && window.innerWidth <= 760){
      active.scrollIntoView({behavior:"smooth",inline:"center",block:"nearest"});
    }
  }

  function syncClock(){
    const d = new Date();
    const h = String(d.getUTCHours()).padStart(2,"0");
    const m = String(d.getUTCMinutes()).padStart(2,"0");
    const el = document.getElementById("retro-utc");
    if(el) el.textContent = `${h}:${m}`;
    const pill = document.getElementById("avis-profile-pill");
    const ac = document.getElementById("retro-ac");
    if(pill && ac){
      const txt = pill.textContent.replace(/^.*?:/,"").trim();
      if(txt) ac.textContent = txt.toUpperCase().slice(0,8);
    }
  }

  function translateTextNode(node){
    const raw = node.nodeValue;
    if(!raw || !raw.trim()) return;
    let out = raw;
    ruMap.forEach((ru,en)=>{
      const safe = en.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
      out = out.replace(new RegExp("\\b"+safe+"\\b","g"), ru);
    });
    if(out !== raw) node.nodeValue = out;
  }

  function translateVisible(root){
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
      acceptNode(node){
        const p = node.parentElement;
        if(!p || ["SCRIPT","STYLE","TEXTAREA","INPUT"].includes(p.tagName)) return NodeFilter.FILTER_REJECT;
        return NodeFilter.FILTER_ACCEPT;
      }
    });
    const nodes = [];
    while(walker.nextNode()) nodes.push(walker.currentNode);
    nodes.forEach(translateTextNode);
  }

  function observeTranslations(){
    const mo = new MutationObserver((mutations)=>{
      for(const m of mutations){
        m.addedNodes.forEach(n=>{
          if(n.nodeType === 3) translateTextNode(n);
          if(n.nodeType === 1) translateVisible(n);
        });
        if(m.type === "attributes" && m.target) translateVisible(m.target);
      }
      const active = document.querySelector(".page.active")?.id?.replace(/^tab-/,"");
      if(active) setActive(active);
    });
    mo.observe(document.body,{childList:true,subtree:true,attributes:false});
  }

  if(document.readyState === "loading"){
    document.addEventListener("DOMContentLoaded", buildShell);
  } else {
    buildShell();
  }
})();

