(function(){
  function getEl(id){
    return document.getElementById(id);
  }

  function text(id){
    var el = getEl(id);
    return el ? el.textContent.replace(/\s+/g," ").trim() : "—";
  }

  function value(id){
    var el = getEl(id);
    return el ? (el.value || "0") : "0";
  }

  function setText(id, val){
    var el = getEl(id);
    if(el) el.textContent = val;
  }

  function deg(v){
    var n = parseFloat(v);
    if(isNaN(n)) n = 0;
    n = ((n % 360) + 360) % 360;
    return n;
  }

  function ensureWindVisual(){
    var tab = getEl("tab-calc");
    if(!tab || getEl("wind-visual-safe")) return;

    var wrap = document.createElement("div");
    wrap.className = "wind-visual-safe";
    wrap.id = "wind-visual-safe";

    wrap.innerHTML =
      '<section class="wind-safe-hero">' +
        '<div class="wind-safe-copy">' +
          '<div class="wind-safe-kicker">НАВИГАЦИОННЫЙ МОДУЛЬ · ВЕТЕР И КУРС</div>' +
          '<div class="wind-safe-title">Ветровой прибор</div>' +
          '<div class="wind-safe-sub">Визуальный индикатор дублирует данные стандартного расчёта. Зелёная стрелка показывает путевой угол, жёлтая — направление ветра. Формулы и исходные поля ниже остаются прежними.</div>' +
          '<div class="wind-safe-legend">' +
            '<span class="wind-safe-chip"><b>Зелёная</b> маршрут</span>' +
            '<span class="wind-safe-chip am"><b>Жёлтая</b> ветер</span>' +
            '<span class="wind-safe-chip"><b>LCD</b> обзор</span>' +
          '</div>' +
        '</div>' +
        '<div class="wind-safe-radar-box">' +
          '<div class="wind-safe-dial">' +
            '<div class="wind-safe-mark n">N</div>' +
            '<div class="wind-safe-mark e">E</div>' +
            '<div class="wind-safe-mark s">S</div>' +
            '<div class="wind-safe-mark w">W</div>' +
            '<div class="wind-safe-arrow route" id="wind-safe-route-arrow"></div>' +
            '<div class="wind-safe-arrow wind" id="wind-safe-wind-arrow"></div>' +
            '<div class="wind-safe-center"></div>' +
          '</div>' +
          '<div class="wind-safe-dial-label">COURSE / WIND<br>VISUAL DUPLICATOR</div>' +
        '</div>' +
      '</section>' +

      '<section class="wind-safe-kpis">' +
        '<div class="wind-safe-kpi"><span>Курс</span><b id="wind-safe-hdg">—</b><small>КУ / ИК</small></div>' +
        '<div class="wind-safe-kpi"><span>Угол сноса</span><b id="wind-safe-drift">—</b><small>УС</small></div>' +
        '<div class="wind-safe-kpi"><span>Путевая</span><b id="wind-safe-gs">—</b><small>Vпутевая</small></div>' +
        '<div class="wind-safe-kpi"><span>Время</span><b id="wind-safe-time">—</b><small>на дистанцию</small></div>' +
      '</section>' +

      '<section class="wind-safe-inputs">' +
        '<div class="wind-safe-input-card"><span>Путевой угол</span><b id="wind-safe-pu">—</b></div>' +
        '<div class="wind-safe-input-card"><span>Ветер</span><b id="wind-safe-wind">—</b></div>' +
        '<div class="wind-safe-input-card"><span>Vпр</span><b id="wind-safe-vias">—</b></div>' +
        '<div class="wind-safe-input-card"><span>Дистанция</span><b id="wind-safe-dist">—</b></div>' +
      '</section>' +

      '<div class="wind-safe-note"><b>Важно:</b> это только визуальный слой. Все расчёты выполняются старой логикой приложения, а этот блок лишь красиво показывает уже рассчитанные значения.</div>';

    tab.insertBefore(wrap, tab.firstChild);
  }

  function updateWindVisual(){
    if(!getEl("wind-visual-safe")) return;

    var pu = deg(value("pu"));
    var wdir = deg(value("wdir"));
    var wspd = value("wspd");
    var vias = value("vias");
    var dist = value("dist");

    var routeArrow = getEl("wind-safe-route-arrow");
    var windArrow = getEl("wind-safe-wind-arrow");

    if(routeArrow) routeArrow.style.transform = "rotate(" + pu + "deg)";
    if(windArrow) windArrow.style.transform = "rotate(" + wdir + "deg)";

    setText("wind-safe-hdg", text("r-hdg"));
    setText("wind-safe-drift", text("r-drift"));
    setText("wind-safe-gs", text("r-gs"));
    setText("wind-safe-time", text("r-time"));

    setText("wind-safe-pu", Math.round(pu) + "°");
    setText("wind-safe-wind", Math.round(wdir) + "° / " + wspd + " км/ч");
    setText("wind-safe-vias", vias + " км/ч");
    setText("wind-safe-dist", dist + " км");
  }

  function bindInputs(){
    var ids = ["pu","vias","wdir","wspd","dist","vcorr"];
    for(var i=0;i<ids.length;i++){
      var el = getEl(ids[i]);
      if(!el || el.getAttribute("data-wind-safe-bound") === "1") continue;

      el.setAttribute("data-wind-safe-bound","1");
      el.addEventListener("input", function(){
        setTimeout(updateWindVisual, 0);
      });
      el.addEventListener("change", function(){
        setTimeout(updateWindVisual, 0);
      });
    }
  }

  function patchCalc(){
    if(window.__windSafeCalcPatched) return;
    window.__windSafeCalcPatched = true;

    if(typeof window.calc === "function"){
      var oldCalc = window.calc;
      window.calc = function(){
        var result = oldCalc.apply(this, arguments);
        setTimeout(updateWindVisual, 0);
        return result;
      };
    }
  }

  function patchShowTab(){
    if(window.__windSafeShowTabPatched) return;
    window.__windSafeShowTabPatched = true;

    if(typeof window.showTab === "function"){
      var oldShowTab = window.showTab;
      window.showTab = function(){
        var result = oldShowTab.apply(this, arguments);
        setTimeout(function(){
          ensureWindVisual();
          bindInputs();
          updateWindVisual();
        }, 0);
        return result;
      };
    }
  }

  function init(){
    ensureWindVisual();
    bindInputs();
    patchCalc();
    patchShowTab();

    setTimeout(updateWindVisual, 50);
    setTimeout(updateWindVisual, 400);
    setInterval(updateWindVisual, 2000);
  }

  if(document.readyState === "loading"){
    document.addEventListener("DOMContentLoaded", init);
  }else{
    init();
  }
})();

// ===== block =====

(function(){
  var parsedPoints = [];

  function el(id){ return document.getElementById(id); }

  function log(msg){
    var box = el("ri-log");
    if(!box) return;
    var time = new Date().toLocaleTimeString();
    box.textContent += "[" + time + "] " + msg + "\n";
    box.scrollTop = box.scrollHeight;
  }

  function setText(id, val){
    var x = el(id);
    if(x) x.textContent = val;
  }

  function rad(d){ return d * Math.PI / 180; }
  function deg(r){ return r * 180 / Math.PI; }

  function distanceKm(a,b){
    var R = 6371;
    var dLat = rad(b.lat - a.lat);
    var dLon = rad(b.lon - a.lon);
    var lat1 = rad(a.lat);
    var lat2 = rad(b.lat);
    var s = Math.sin(dLat/2)*Math.sin(dLat/2) +
            Math.cos(lat1)*Math.cos(lat2)*Math.sin(dLon/2)*Math.sin(dLon/2);
    return 2 * R * Math.atan2(Math.sqrt(s), Math.sqrt(1-s));
  }

  function bearingDeg(a,b){
    var lat1 = rad(a.lat), lat2 = rad(b.lat);
    var dLon = rad(b.lon - a.lon);
    var y = Math.sin(dLon) * Math.cos(lat2);
    var x = Math.cos(lat1)*Math.sin(lat2) - Math.sin(lat1)*Math.cos(lat2)*Math.cos(dLon);
    var brng = (deg(Math.atan2(y,x)) + 360) % 360;
    return brng;
  }

  function parseDmsPart(part){
    // Поддерживает: N55 45.3, 55°45'30"N, 55 45 30 N, N55.7558
    var sign = 1;
    part = String(part).trim().replace(/,/g, ".");
    if(/[SWЮЗ]/i.test(part)) sign = -1;

    var nums = part.match(/-?\d+(?:\.\d+)?/g);
    if(!nums || !nums.length) return null;

    var d = Math.abs(parseFloat(nums[0]));
    var m = nums[1] ? parseFloat(nums[1]) : 0;
    var s = nums[2] ? parseFloat(nums[2]) : 0;

    var val = d + m/60 + s/3600;
    if(/^-/.test(nums[0])) sign = -1;
    return sign * val;
  }

  function parseLine(line, index){
    var original = line;
    line = String(line).trim();
    if(!line) return null;

    // Убираем HTML/XML теги для GPX/KML строк
    var clean = line.replace(/<[^>]+>/g, " ").replace(/\s+/g, " ").trim();

    // GPX/KML атрибуты lat/lon
    var latAttr = line.match(/\blat=["'](-?\d+(?:\.\d+)?)["']/i);
    var lonAttr = line.match(/\b(?:lon|lng)=["'](-?\d+(?:\.\d+)?)["']/i);
    if(latAttr && lonAttr){
      return {
        name: "WP" + (index+1),
        lat: parseFloat(latAttr[1]),
        lon: parseFloat(lonAttr[1]),
        raw: original
      };
    }

    // JSON-like lat/lon
    var latJson = clean.match(/(?:lat|latitude)\s*[:=]\s*(-?\d+(?:\.\d+)?)/i);
    var lonJson = clean.match(/(?:lon|lng|longitude)\s*[:=]\s*(-?\d+(?:\.\d+)?)/i);
    if(latJson && lonJson){
      return {
        name: extractName(clean, index),
        lat: parseFloat(latJson[1]),
        lon: parseFloat(lonJson[1]),
        raw: original
      };
    }

    // Decimal pair: 55.7558, 37.6173 or WP1 55.7558 37.6173
    var nums = clean.match(/-?\d+(?:\.\d+)?/g);
    if(nums && nums.length >= 2){
      for(var i=0;i<nums.length-1;i++){
        var a = parseFloat(nums[i]);
        var b = parseFloat(nums[i+1]);
        if(isLatLon(a,b)){
          return { name: extractName(clean, index), lat:a, lon:b, raw:original };
        }
        if(isLatLon(b,a)){
          return { name: extractName(clean, index), lat:b, lon:a, raw:original };
        }
      }
    }

    // DMS patterns with N/S and E/W chunks
    var latChunk = clean.match(/([NSСЮ]\s*\d{1,2}(?:[°\s]+(?:\d{1,2}(?:\.\d+)?)?)?(?:['\s]+(?:\d{1,2}(?:\.\d+)?)?)?|"?\s*|\d{1,2}(?:\.\d+)?\s*[NSСЮ])/i);
    var lonChunk = clean.match(/([EWВЗ]\s*\d{1,3}(?:[°\s]+(?:\d{1,2}(?:\.\d+)?)?)?(?:['\s]+(?:\d{1,2}(?:\.\d+)?)?)?|"?\s*|\d{1,3}(?:\.\d+)?\s*[EWВЗ])/i);
    if(latChunk && lonChunk){
      var lat = parseDmsPart(latChunk[0]);
      var lon = parseDmsPart(lonChunk[0]);
      if(lat !== null && lon !== null && isLatLon(lat,lon)){
        return { name: extractName(clean, index), lat:lat, lon:lon, raw:original };
      }
    }

    return null;
  }

  function isLatLon(lat, lon){
    return isFinite(lat) && isFinite(lon) && Math.abs(lat) <= 90 && Math.abs(lon) <= 180;
  }

  function extractName(line, index){
    var name = line
      .replace(/lat(?:itude)?\s*[:=]\s*-?\d+(?:\.\d+)?/ig, "")
      .replace(/(?:lon|lng|longitude)\s*[:=]\s*-?\d+(?:\.\d+)?/ig, "")
      .replace(/[NSWEСЮВЗ]?\s*-?\d+(?:\.\d+)?[°'"]?/ig, "")
      .replace(/[,;|]+/g, " ")
      .replace(/\s+/g, " ")
      .trim();

    if(!name || name.length < 2) return "WP" + (index+1);
    if(name.length > 20) name = name.slice(0,20);
    return name;
  }

  function parseAll(){
    parsedPoints = [];
    var input = el("ri-input");
    if(!input) return;

    var text = input.value || "";
    var lines = text.split(/\n+/);

    // Если GPX/KML в одну строку, дробим по trkpt/wpt/Placemark приблизительно
    if(lines.length < 2 && /lat=["']/i.test(text)){
      lines = text.replace(/</g, "\n<").split(/\n+/);
    }

    for(var i=0;i<lines.length;i++){
      var p = parseLine(lines[i], parsedPoints.length);
      if(p && isLatLon(p.lat,p.lon)){
        parsedPoints.push(p);
      }
    }

    renderTable();
    updateStats();

    log("Распознано точек: " + parsedPoints.length);
    if(parsedPoints.length < 2){
      log("Для маршрута нужно минимум 2 точки. Поддерживаются форматы: decimal, lat/lon, GPX/KML lat/lon.");
    }
  }

  function renderTable(){
    var body = el("ri-table-body");
    if(!body) return;

    body.innerHTML = "";

    for(var i=0;i<parsedPoints.length;i++){
      var p = parsedPoints[i];
      var leg = "";
      var brg = "";

      if(i > 0){
        var prev = parsedPoints[i-1];
        leg = distanceKm(prev,p).toFixed(1);
        brg = bearingDeg(prev,p).toFixed(0) + "°";
      }else{
        leg = "—";
        brg = "—";
      }

      var tr = document.createElement("tr");
      tr.innerHTML =
        '<td>'+(i+1)+'</td>' +
        '<td>'+escapeHtml(p.name)+'</td>' +
        '<td class="num">'+p.lat.toFixed(6)+'</td>' +
        '<td class="num">'+p.lon.toFixed(6)+'</td>' +
        '<td class="num">'+brg+'</td>' +
        '<td class="num">'+leg+'</td>';
      body.appendChild(tr);
    }
  }

  function updateStats(){
    var total = 0;
    for(var i=1;i<parsedPoints.length;i++){
      total += distanceKm(parsedPoints[i-1], parsedPoints[i]);
    }

    setText("ri-kpi-points", parsedPoints.length);
    setText("ri-kpi-distance", parsedPoints.length > 1 ? total.toFixed(1) + " км" : "—");
    setText("ri-kpi-first", parsedPoints.length ? parsedPoints[0].name : "—");
  }

  function escapeHtml(s){
    return String(s).replace(/[&<>"']/g, function(c){
      return {"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c];
    });
  }

  function copyResult(){
    if(!parsedPoints.length){
      parseAll();
    }

    var out = parsedPoints.map(function(p,i){
      return (i+1) + ". " + p.name + " " + p.lat.toFixed(6) + ", " + p.lon.toFixed(6);
    }).join("\n");

    if(!out){
      log("Нет точек для копирования.");
      return;
    }

    if(navigator.clipboard && navigator.clipboard.writeText){
      navigator.clipboard.writeText(out).then(function(){
        log("Маршрут скопирован в буфер.");
      }).catch(function(){
        fallbackCopy(out);
      });
    }else{
      fallbackCopy(out);
    }
  }

  function fallbackCopy(text){
    var area = document.createElement("textarea");
    area.value = text;
    document.body.appendChild(area);
    area.select();
    try{
      document.execCommand("copy");
      log("Маршрут скопирован в буфер.");
    }catch(e){
      log("Не удалось скопировать автоматически. Выделите результат вручную.");
    }
    document.body.removeChild(area);
  }

  function addToRoute(){
    if(!parsedPoints.length) parseAll();

    if(parsedPoints.length < 2){
      log("Не хватает точек для добавления в маршрут.");
      return;
    }

    var added = false;

    // Попытка найти таблицу маршрута исходного приложения и заполнить первые legs.
    // Если структура не совпадёт — просто сохраняем в localStorage.
    try{
      var routeText = parsedPoints.map(function(p,i){
        return (i+1) + ". " + p.name + " " + p.lat.toFixed(6) + "," + p.lon.toFixed(6);
      }).join("\n");

      localStorage.setItem("aviscalc_imported_route", routeText);
      localStorage.setItem("aviscalc_imported_route_json", JSON.stringify(parsedPoints));

      log("Маршрут сохранён в localStorage AvisCalc.");
      log("Следующий шаг: можно сделать отдельное отображение импортированного маршрута во вкладке «Маршрут».");

      added = true;
    }catch(e){
      log("Ошибка сохранения маршрута: " + e.message);
    }

    if(added && typeof window.showTab === "function"){
      log("Открываю вкладку «Маршрут».");
      setTimeout(function(){ window.showTab("route"); }, 450);
    }
  }

  function clearAll(){
    var input = el("ri-input");
    if(input) input.value = "";
    parsedPoints = [];
    renderTable();
    updateStats();
    var l = el("ri-log");
    if(l) l.textContent = "";
    log("Очищено.");
  }

  function fillExample(){
    var input = el("ri-input");
    if(!input) return;

    input.value =
      "Москва 55.7558, 37.6173\n" +
      "Точка-2 56.0100, 38.2400\n" +
      "Точка-3 lat=56.3200 lon=39.1200\n" +
      "Финиш N56 45.000 E040 12.000";
    parseAll();
  }

  function ensureTab(){
    if(el("tab-route-import")) return;

    var scroll = document.querySelector(".scroll");
    if(!scroll) return;

    var page = document.createElement("div");
    page.className = "page";
    page.id = "tab-route-import";

    page.innerHTML =
      '<div class="route-import">' +
        '<section class="ri-hero">' +
          '<div class="ri-hero-content">' +
            '<div class="ri-kicker">МАРШРУТНЫЙ ИМПОРТ · AIRCOM / GPX / ТЕКСТ</div>' +
            '<div class="ri-title">Импорт маршрута</div>' +
            '<div class="ri-subtitle">Вставь координаты, точки маршрута, фрагмент GPX/KML или текст из другого приложения. AvisCalc распознает точки, посчитает расстояния между legs и подготовит маршрут для дальнейшей работы.</div>' +
          '</div>' +
        '</section>' +

        '<section class="ri-grid">' +
          '<div class="ri-panel">' +
            '<div class="ri-panel-head">Вставка данных</div>' +
            '<div class="ri-panel-body">' +
              '<textarea class="ri-textarea" id="ri-input" placeholder="Примеры:\\nWP1 55.7558, 37.6173\\nWP2 lat=56.0100 lon=38.2400\\nN56 45.000 E040 12.000\\nили GPX/KML с lat/lon"></textarea>' +
              '<div class="ri-actions">' +
                '<button class="ri-btn primary" id="ri-parse">Распознать</button>' +
                '<button class="ri-btn" id="ri-example">Пример</button>' +
                '<button class="ri-btn" id="ri-copy">Копировать</button>' +
                '<button class="ri-btn warn" id="ri-clear">Очистить</button>' +
              '</div>' +
            '</div>' +
          '</div>' +

          '<div class="ri-panel">' +
            '<div class="ri-panel-head">Поддерживаемые форматы</div>' +
            '<div class="ri-panel-body">' +
              '<div class="ri-format-grid">' +
                '<div class="ri-format"><b>Decimal</b><br>55.7558, 37.6173</div>' +
                '<div class="ri-format"><b>Lat/Lon</b><br>lat=55.7558 lon=37.6173</div>' +
                '<div class="ri-format"><b>DMS</b><br>N56 45.000 E040 12.000</div>' +
                '<div class="ri-format"><b>GPX/KML</b><br>lat="..." lon="..."</div>' +
              '</div>' +
              '<div class="ri-kpi-grid">' +
                '<div class="ri-kpi"><span>Точек</span><b id="ri-kpi-points">0</b></div>' +
                '<div class="ri-kpi"><span>Дистанция</span><b id="ri-kpi-distance">—</b></div>' +
                '<div class="ri-kpi"><span>Старт</span><b id="ri-kpi-first">—</b></div>' +
              '</div>' +
              '<button class="ri-btn primary" id="ri-add-route">Сохранить / в маршрут</button>' +
            '</div>' +
          '</div>' +
        '</section>' +

        '<section class="ri-panel">' +
          '<div class="ri-panel-head">Распознанные точки</div>' +
          '<div class="ri-panel-body">' +
            '<div class="ri-table-wrap">' +
              '<table class="ri-table">' +
                '<thead><tr><th>#</th><th>Точка</th><th>LAT</th><th>LON</th><th>Курс</th><th>Leg км</th></tr></thead>' +
                '<tbody id="ri-table-body"></tbody>' +
              '</table>' +
            '</div>' +
          '</div>' +
        '</section>' +

        '<section class="ri-panel">' +
          '<div class="ri-panel-head">Лог</div>' +
          '<div class="ri-panel-body"><div class="ri-log" id="ri-log">IMPORT READY\\nВставь координаты и нажми «Распознать».\\n</div></div>' +
        '</section>' +

        '<div class="ri-note"><b>Важно:</b> эта функция не зависит от IP/порта и работает прямо в браузере. Для Aircom можно использовать любой текстовый экспорт, скопированные координаты или маршрутные точки.</div>' +
      '</div>';

    scroll.appendChild(page);

    bindButtons();
  }

  function bindButtons(){
    var parseBtn = el("ri-parse");
    var exampleBtn = el("ri-example");
    var copyBtn = el("ri-copy");
    var clearBtn = el("ri-clear");
    var addBtn = el("ri-add-route");
    var input = el("ri-input");

    if(parseBtn && !parseBtn.dataset.bound){ parseBtn.dataset.bound = "1"; parseBtn.addEventListener("click", parseAll); }
    if(exampleBtn && !exampleBtn.dataset.bound){ exampleBtn.dataset.bound = "1"; exampleBtn.addEventListener("click", fillExample); }
    if(copyBtn && !copyBtn.dataset.bound){ copyBtn.dataset.bound = "1"; copyBtn.addEventListener("click", copyResult); }
    if(clearBtn && !clearBtn.dataset.bound){ clearBtn.dataset.bound = "1"; clearBtn.addEventListener("click", clearAll); }
    if(addBtn && !addBtn.dataset.bound){ addBtn.dataset.bound = "1"; addBtn.addEventListener("click", addToRoute); }
    if(input && !input.dataset.bound){
      input.dataset.bound = "1";
      input.addEventListener("input", function(){
        clearTimeout(input._riTimer);
        input._riTimer = setTimeout(parseAll, 500);
      });
    }
  }

  function addNavButton(){
    if(document.querySelector('.retro-nav-btn[data-tab="route-import"]')) return;

    var nav = document.querySelector(".retro-nav");
    if(!nav) return;

    var btn = document.createElement("button");
    btn.className = "retro-nav-btn";
    btn.setAttribute("data-tab","route-import");
    btn.innerHTML = '<span class="ico">⇥</span><span><b>Импорт</b><small>Маршрут</small></span>';

    btn.addEventListener("click", function(){
      if(typeof window.showTab === "function"){
        window.showTab("route-import");
      }else{
        var pages = document.querySelectorAll(".page");
        for(var i=0;i<pages.length;i++) pages[i].classList.remove("active");
        var page = el("tab-route-import");
        if(page) page.classList.add("active");
      }

      var buttons = document.querySelectorAll(".retro-nav-btn");
      for(var j=0;j<buttons.length;j++){
        buttons[j].classList.toggle("active", buttons[j].getAttribute("data-tab") === "route-import");
      }
    });

    // Ставим рядом с маршрутом, если нашли кнопку маршрута
    var routeBtn = document.querySelector('.retro-nav-btn[data-tab="route"]');
    if(routeBtn && routeBtn.parentNode === nav && routeBtn.nextSibling){
      nav.insertBefore(btn, routeBtn.nextSibling);
    }else{
      nav.appendChild(btn);
    }
  }

  function patchShowTab(){
    if(window.__routeImportShowTabPatched) return;
    window.__routeImportShowTabPatched = true;

    if(typeof window.showTab === "function"){
      var oldShowTab = window.showTab;
      window.showTab = function(t){
        ensureTab();
        var result = oldShowTab.apply(this, arguments);

        if(t === "route-import"){
          var pages = document.querySelectorAll(".page");
          for(var i=0;i<pages.length;i++){
            pages[i].classList.toggle("active", pages[i].id === "tab-route-import");
          }

          var buttons = document.querySelectorAll(".retro-nav-btn");
          for(var j=0;j<buttons.length;j++){
            buttons[j].classList.toggle("active", buttons[j].getAttribute("data-tab") === "route-import");
          }

          var scroll = document.querySelector(".scroll");
          if(scroll) scroll.scrollTop = 0;
        }

        return result;
      };
    }
  }

  function init(){
    ensureTab();
    addNavButton();
    patchShowTab();
    updateStats();
    log("Модуль импорта маршрута загружен.");
  }

  if(document.readyState === "loading"){
    document.addEventListener("DOMContentLoaded", init);
  }else{
    init();
  }
})();

