(function(){
  function el(id){ return document.getElementById(id); }

  function rad(d){ return d * Math.PI / 180; }
  function deg(r){ return r * 180 / Math.PI; }

  function distanceKm(a,b){
    var R = 6371;
    var dLat = rad(b.lat - a.lat);
    var dLon = rad(b.lon - a.lon);
    var lat1 = rad(a.lat);
    var lat2 = rad(b.lat);
    var s = Math.sin(dLat/2)*Math.sin(dLat/2) +
            Math.cos(lat1)*Math.cos(lat2)*Math.sin(dLon/2)*Math.sin(dLon/2);
    return 2 * R * Math.atan2(Math.sqrt(s), Math.sqrt(1-s));
  }

  function bearingDeg(a,b){
    var lat1 = rad(a.lat), lat2 = rad(b.lat);
    var dLon = rad(b.lon - a.lon);
    var y = Math.sin(dLon) * Math.cos(lat2);
    var x = Math.cos(lat1)*Math.sin(lat2) - Math.sin(lat1)*Math.cos(lat2)*Math.cos(dLon);
    return (deg(Math.atan2(y,x)) + 360) % 360;
  }

  function getImported(){
    try{
      var raw = localStorage.getItem("aviscalc_imported_route_json");
      if(!raw) return [];
      var arr = JSON.parse(raw);
      if(!Array.isArray(arr)) return [];
      return arr.filter(function(p){
        return p && isFinite(p.lat) && isFinite(p.lon);
      });
    }catch(e){
      return [];
    }
  }

  function ensurePanel(){
    var routeTab = el("tab-route");
    if(!routeTab || el("imported-route-panel")) return;

    var panel = document.createElement("section");
    panel.className = "imported-route-panel";
    panel.id = "imported-route-panel";
    panel.innerHTML =
      '<div class="imported-route-head">' +
        '<span>Импортированный маршрут</span>' +
        '<small id="ir-head-status">ожидание данных</small>' +
      '</div>' +
      '<div class="imported-route-body" id="ir-body">' +
        '<div class="ir-empty"><b>Нет импортированного маршрута.</b><br>Открой вкладку «Импорт», вставь координаты и нажми «Сохранить / в маршрут».</div>' +
      '</div>';

    routeTab.insertBefore(panel, routeTab.firstChild);
  }

  function renderImported(){
    ensurePanel();

    var body = el("ir-body");
    if(!body) return;

    var pts = getImported();
    var status = el("ir-head-status");

    if(!pts.length){
      if(status) status.textContent = "нет данных";
      body.innerHTML = '<div class="ir-empty"><b>Нет импортированного маршрута.</b><br>Открой вкладку «Импорт», вставь координаты и нажми «Сохранить / в маршрут».</div>';
      return;
    }

    var total = 0;
    for(var i=1;i<pts.length;i++){
      total += distanceKm(pts[i-1], pts[i]);
    }

    if(status) status.textContent = pts.length + " точек";

    var rows = "";
    for(var j=0;j<pts.length;j++){
      var p = pts[j];
      var leg = "—";
      var brg = "—";

      if(j > 0){
        leg = distanceKm(pts[j-1], p).toFixed(1);
        brg = bearingDeg(pts[j-1], p).toFixed(0) + "°";
      }

      rows += '<tr>' +
        '<td>' + (j+1) + '</td>' +
        '<td>' + escapeHtml(p.name || ("WP"+(j+1))) + '</td>' +
        '<td class="num">' + Number(p.lat).toFixed(6) + '</td>' +
        '<td class="num">' + Number(p.lon).toFixed(6) + '</td>' +
        '<td class="num">' + brg + '</td>' +
        '<td class="num">' + leg + '</td>' +
      '</tr>';
    }

    body.innerHTML =
      '<div class="ir-summary-grid">' +
        '<div class="ir-summary"><span>Точек</span><b>' + pts.length + '</b></div>' +
        '<div class="ir-summary"><span>Общая дистанция</span><b>' + (pts.length > 1 ? total.toFixed(1) + " км" : "—") + '</b></div>' +
        '<div class="ir-summary"><span>Старт</span><b>' + escapeHtml(pts[0].name || "WP1") + '</b></div>' +
        '<div class="ir-summary"><span>Финиш</span><b>' + escapeHtml(pts[pts.length-1].name || ("WP"+pts.length)) + '</b></div>' +
      '</div>' +

      '<div class="ir-table-wrap">' +
        '<table class="ir-table">' +
          '<thead><tr><th>#</th><th>Точка</th><th>LAT</th><th>LON</th><th>Курс</th><th>Leg км</th></tr></thead>' +
          '<tbody>' + rows + '</tbody>' +
        '</table>' +
      '</div>' +

      '<div class="ir-actions">' +
        '<button class="ir-btn primary" id="ir-refresh">Обновить</button>' +
        '<button class="ir-btn" id="ir-copy">Копировать</button>' +
        '<button class="ir-btn warn" id="ir-clear">Очистить импорт</button>' +
      '</div>';

    bindButtons();
  }

  function bindButtons(){
    var refresh = el("ir-refresh");
    var copy = el("ir-copy");
    var clear = el("ir-clear");

    if(refresh && !refresh.dataset.bound){
      refresh.dataset.bound = "1";
      refresh.addEventListener("click", renderImported);
    }

    if(copy && !copy.dataset.bound){
      copy.dataset.bound = "1";
      copy.addEventListener("click", copyImported);
    }

    if(clear && !clear.dataset.bound){
      clear.dataset.bound = "1";
      clear.addEventListener("click", function(){
        try{
          localStorage.removeItem("aviscalc_imported_route");
          localStorage.removeItem("aviscalc_imported_route_json");
        }catch(e){}
        renderImported();
      });
    }
  }

  function copyImported(){
    var pts = getImported();
    if(!pts.length) return;

    var out = pts.map(function(p,i){
      return (i+1) + ". " + (p.name || ("WP"+(i+1))) + " " + Number(p.lat).toFixed(6) + ", " + Number(p.lon).toFixed(6);
    }).join("\n");

    if(navigator.clipboard && navigator.clipboard.writeText){
      navigator.clipboard.writeText(out);
    }else{
      var area = document.createElement("textarea");
      area.value = out;
      document.body.appendChild(area);
      area.select();
      try{ document.execCommand("copy"); }catch(e){}
      document.body.removeChild(area);
    }
  }

  function escapeHtml(s){
    return String(s).replace(/[&<>"']/g, function(c){
      return {"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c];
    });
  }

  function patchShowTab(){
    if(window.__importedRouteDisplayPatched) return;
    window.__importedRouteDisplayPatched = true;

    if(typeof window.showTab === "function"){
      var oldShowTab = window.showTab;
      window.showTab = function(t){
        var result = oldShowTab.apply(this, arguments);
        if(t === "route"){
          setTimeout(renderImported, 80);
        }
        return result;
      };
    }
  }

  function patchStorageSet(){
    if(window.__importedRouteStoragePatched) return;
    window.__importedRouteStoragePatched = true;

    var oldSet = localStorage.setItem;
    localStorage.setItem = function(k,v){
      var r = oldSet.apply(this, arguments);
      if(k === "aviscalc_imported_route_json" || k === "aviscalc_imported_route"){
        setTimeout(renderImported, 80);
      }
      return r;
    };
  }

  function init(){
    ensurePanel();
    renderImported();
    patchShowTab();
    try{ patchStorageSet(); }catch(e){}
    setInterval(function(){
      var active = document.querySelector(".page.active");
      if(active && active.id === "tab-route"){
        renderImported();
      }
    }, 2500);
  }

  if(document.readyState === "loading"){
    document.addEventListener("DOMContentLoaded", init);
  }else{
    init();
  }
})();

