(function(){
  var parsedZones = [];

  function el(id){ return document.getElementById(id); }

  function log(msg){
    var box = el("zi-log");
    if(!box) return;
    var time = new Date().toLocaleTimeString();
    box.textContent += "[" + time + "] " + msg + "\n";
    box.scrollTop = box.scrollHeight;
  }

  function setText(id,val){
    var x = el(id);
    if(x) x.textContent = val;
  }

  function rad(d){ return d * Math.PI / 180; }

  function distanceKm(a,b){
    var R = 6371;
    var dLat = rad(b.lat - a.lat);
    var dLon = rad(b.lon - a.lon);
    var lat1 = rad(a.lat);
    var lat2 = rad(b.lat);
    var s = Math.sin(dLat/2)*Math.sin(dLat/2) +
            Math.cos(lat1)*Math.cos(lat2)*Math.sin(dLon/2)*Math.sin(dLon/2);
    return 2 * R * Math.atan2(Math.sqrt(s), Math.sqrt(1-s));
  }

  function polygonPerimeter(points){
    if(!points || points.length < 2) return 0;
    var total = 0;
    for(var i=1;i<points.length;i++) total += distanceKm(points[i-1], points[i]);
    if(points.length > 2) total += distanceKm(points[points.length-1], points[0]);
    return total;
  }

  function polygonAreaKm2(points){
    if(!points || points.length < 3) return 0;
    // Простая equirectangular-проекция для приблизительной площади.
    var R = 6371;
    var lat0 = 0;
    for(var i=0;i<points.length;i++) lat0 += points[i].lat;
    lat0 = rad(lat0 / points.length);

    var xy = points.map(function(p){
      return {
        x: R * rad(p.lon) * Math.cos(lat0),
        y: R * rad(p.lat)
      };
    });

    var area = 0;
    for(var j=0;j<xy.length;j++){
      var k = (j + 1) % xy.length;
      area += xy[j].x * xy[k].y - xy[k].x * xy[j].y;
    }
    return Math.abs(area / 2);
  }

  function parseCoordPairs(text){
    var points = [];
    var clean = String(text || "").replace(/,/g, function(match, offset, str){
      // оставляем запятые в координатных парах KML: lon,lat
      return ",";
    });

    // KML coordinates: lon,lat[,alt] lon,lat[,alt]
    var kmlPairs = clean.match(/-?\d+(?:\.\d+)?\s*,\s*-?\d+(?:\.\d+)?(?:\s*,\s*-?\d+(?:\.\d+)?)?/g);
    if(kmlPairs && kmlPairs.length >= 3){
      for(var i=0;i<kmlPairs.length;i++){
        var nums = kmlPairs[i].match(/-?\d+(?:\.\d+)?/g);
        if(nums && nums.length >= 2){
          var a = parseFloat(nums[0]);
          var b = parseFloat(nums[1]);
          // KML обычно lon,lat. Если похоже на lat,lon, переворачиваем.
          if(Math.abs(a) <= 180 && Math.abs(b) <= 90){
            points.push({lat:b, lon:a});
          }else if(Math.abs(a) <= 90 && Math.abs(b) <= 180){
            points.push({lat:a, lon:b});
          }
        }
      }
      return points;
    }

    // Decimal text: строки с lat lon
    var numsAll = clean.match(/-?\d+(?:\.\d+)?/g);
    if(numsAll && numsAll.length >= 6){
      for(var j=0;j<numsAll.length-1;j+=2){
        var x = parseFloat(numsAll[j]);
        var y = parseFloat(numsAll[j+1]);
        if(Math.abs(x) <= 90 && Math.abs(y) <= 180){
          points.push({lat:x, lon:y});
        }else if(Math.abs(x) <= 180 && Math.abs(y) <= 90){
          points.push({lat:y, lon:x});
        }
      }
    }

    return points;
  }

  function extractName(block, idx){
    var name = "";

    var nameTag = String(block).match(/<name[^>]*>([\s\S]*?)<\/name>/i);
    if(nameTag) name = nameTag[1].replace(/<[^>]+>/g," ").trim();

    if(!name){
      var first = String(block).split(/\n/).map(function(s){return s.trim();}).filter(Boolean)[0] || "";
      first = first.replace(/[<>{}\[\]",:]/g," ").replace(/\s+/g," ").trim();
      if(first && !/-?\d/.test(first.slice(0,8))) name = first.slice(0,32);
    }

    if(!name) name = "ZONE-" + (idx+1);
    return name.slice(0,32);
  }

  function parseKml(text){
    var zones = [];
    var blocks = [];

    var placemarks = String(text).match(/<Placemark[\s\S]*?<\/Placemark>/gi);
    if(placemarks && placemarks.length){
      blocks = placemarks;
    }else{
      var coords = String(text).match(/<coordinates[^>]*>[\s\S]*?<\/coordinates>/gi);
      if(coords) blocks = coords;
    }

    for(var i=0;i<blocks.length;i++){
      var block = blocks[i];
      var coordMatch = block.match(/<coordinates[^>]*>([\s\S]*?)<\/coordinates>/i);
      var coordText = coordMatch ? coordMatch[1] : block;
      var pts = parseCoordPairs(coordText);
      if(pts.length >= 3){
        zones.push({
          name: extractName(block, zones.length),
          type: "KML",
          points: pts
        });
      }
    }
    return zones;
  }

  function parseGeoJson(text){
    var zones = [];
    try{
      var obj = JSON.parse(text);
      var features = [];

      if(obj.type === "FeatureCollection") features = obj.features || [];
      else if(obj.type === "Feature") features = [obj];
      else if(obj.type === "Polygon" || obj.type === "MultiPolygon") features = [{type:"Feature", properties:{}, geometry:obj}];

      features.forEach(function(f, idx){
        var g = f.geometry || {};
        var props = f.properties || {};
        var name = props.name || props.title || props.Name || ("ZONE-" + (zones.length+1));

        if(g.type === "Polygon" && g.coordinates && g.coordinates[0]){
          var pts = g.coordinates[0].map(function(pair){
            return {lat: Number(pair[1]), lon: Number(pair[0])};
          }).filter(function(p){ return isFinite(p.lat) && isFinite(p.lon); });

          if(pts.length >= 3) zones.push({name:String(name).slice(0,32), type:"GeoJSON", points:pts});
        }

        if(g.type === "MultiPolygon" && g.coordinates){
          g.coordinates.forEach(function(poly, pidx){
            if(poly && poly[0]){
              var pts = poly[0].map(function(pair){
                return {lat: Number(pair[1]), lon: Number(pair[0])};
              }).filter(function(p){ return isFinite(p.lat) && isFinite(p.lon); });

              if(pts.length >= 3) zones.push({name:String(name).slice(0,28)+"-"+(pidx+1), type:"GeoJSON", points:pts});
            }
          });
        }
      });
    }catch(e){}
    return zones;
  }

  function parseTextZones(text){
    var zones = [];
    var blocks = String(text).split(/\n\s*\n+/);
    if(blocks.length < 2) blocks = [text];

    for(var i=0;i<blocks.length;i++){
      var pts = parseCoordPairs(blocks[i]);
      if(pts.length >= 3){
        zones.push({
          name: extractName(blocks[i], zones.length),
          type:"TEXT",
          points:pts
        });
      }
    }

    return zones;
  }

  function parseZones(){
    parsedZones = [];
    var input = el("zi-input");
    if(!input) return;

    var text = input.value || "";
    var kml = parseKml(text);
    var gj = parseGeoJson(text);
    var txt = parseTextZones(text);

    if(kml.length) parsedZones = kml;
    else if(gj.length) parsedZones = gj;
    else parsedZones = txt;

    renderZoneTable();
    updateZoneStats();
    log("Распознано зон: " + parsedZones.length);

    if(!parsedZones.length){
      log("Не найдено полигонов. Нужны минимум 3 координаты на зону.");
    }
  }

  function updateZoneStats(){
    var totalArea = 0;
    var totalPoints = 0;
    for(var i=0;i<parsedZones.length;i++){
      totalArea += polygonAreaKm2(parsedZones[i].points);
      totalPoints += parsedZones[i].points.length;
    }

    setText("zi-kpi-zones", parsedZones.length);
    setText("zi-kpi-points", totalPoints);
    setText("zi-kpi-area", parsedZones.length ? totalArea.toFixed(1) + " км²" : "—");
  }

  function renderZoneTable(){
    var body = el("zi-table-body");
    if(!body) return;
    body.innerHTML = "";

    parsedZones.forEach(function(z, i){
      var area = polygonAreaKm2(z.points);
      var per = polygonPerimeter(z.points);
      var tr = document.createElement("tr");
      tr.innerHTML =
        '<td>'+(i+1)+'</td>' +
        '<td>'+escapeHtml(z.name)+'</td>' +
        '<td>'+escapeHtml(z.type)+'</td>' +
        '<td class="num">'+z.points.length+'</td>' +
        '<td class="num">'+area.toFixed(1)+'</td>' +
        '<td class="num">'+per.toFixed(1)+'</td>';
      body.appendChild(tr);
    });
  }

  function saveZones(){
    if(!parsedZones.length) parseZones();

    if(!parsedZones.length){
      log("Нет зон для сохранения.");
      return;
    }

    try{
      localStorage.setItem("aviscalc_imported_zones_json", JSON.stringify(parsedZones));
      log("Зоны сохранены в localStorage AvisCalc.");
      log("Открой вкладку «Зоны» — там появится блок импортированных зон.");
      if(typeof window.showTab === "function"){
        setTimeout(function(){ window.showTab("zones"); }, 450);
      }
    }catch(e){
      log("Ошибка сохранения: " + e.message);
    }
  }

  function copyZones(){
    if(!parsedZones.length) parseZones();

    var out = parsedZones.map(function(z,i){
      return (i+1)+". "+z.name+" ["+z.type+"] points="+z.points.length+
        " area="+polygonAreaKm2(z.points).toFixed(1)+"km2";
    }).join("\n");

    if(!out){
      log("Нет зон для копирования.");
      return;
    }

    if(navigator.clipboard && navigator.clipboard.writeText){
      navigator.clipboard.writeText(out).then(function(){ log("Список зон скопирован."); });
    }else{
      var area = document.createElement("textarea");
      area.value = out;
      document.body.appendChild(area);
      area.select();
      try{ document.execCommand("copy"); log("Список зон скопирован."); }catch(e){}
      document.body.removeChild(area);
    }
  }

  function fillExample(){
    var input = el("zi-input");
    if(!input) return;

    input.value =
      "TRAINING-ZONE-1\n" +
      "55.7000, 37.3000\n" +
      "55.9000, 37.3500\n" +
      "55.8500, 37.7000\n" +
      "55.6500, 37.6500\n\n" +
      "ZONE-2 KML style\n" +
      "37.9000,56.0000 38.2000,56.0500 38.2500,55.8500 37.9500,55.8000";
    parseZones();
  }

  function clearZones(){
    var input = el("zi-input");
    if(input) input.value = "";
    parsedZones = [];
    renderZoneTable();
    updateZoneStats();
    var l = el("zi-log");
    if(l) l.textContent = "";
    log("Очищено.");
  }

  function ensureZoneImportTab(){
    if(el("tab-zone-import")) return;

    var scroll = document.querySelector(".scroll");
    if(!scroll) return;

    var page = document.createElement("div");
    page.className = "page";
    page.id = "tab-zone-import";

    page.innerHTML =
      '<div class="zone-import">' +
        '<section class="zi-hero">' +
          '<div class="zi-hero-content">' +
            '<div class="zi-kicker">ИМПОРТ ВОЗДУШНЫХ ЗОН · KML / GEOJSON / ТЕКСТ</div>' +
            '<div class="zi-title">Импорт зон</div>' +
            '<div class="zi-subtitle">Вставь KML, GeoJSON или простой список координат полигона. AvisCalc распознает зоны, посчитает примерную площадь и периметр, затем сохранит их локально для вкладки «Зоны».</div>' +
          '</div>' +
        '</section>' +

        '<section class="zi-grid">' +
          '<div class="zi-panel">' +
            '<div class="zi-panel-head">Вставка данных</div>' +
            '<div class="zi-panel-body">' +
              '<textarea class="zi-textarea" id="zi-input" placeholder="Примеры:\\nZONE-1\\n55.7000, 37.3000\\n55.9000, 37.3500\\n55.8500, 37.7000\\n\\nKML: <coordinates>37.3,55.7 37.7,55.8 37.5,55.9</coordinates>\\nGeoJSON: Polygon / FeatureCollection"></textarea>' +
              '<div class="zi-actions">' +
                '<button class="zi-btn primary" id="zi-parse">Распознать</button>' +
                '<button class="zi-btn" id="zi-example">Пример</button>' +
                '<button class="zi-btn" id="zi-copy">Копировать</button>' +
                '<button class="zi-btn warn" id="zi-clear">Очистить</button>' +
              '</div>' +
            '</div>' +
          '</div>' +

          '<div class="zi-panel">' +
            '<div class="zi-panel-head">Форматы и статистика</div>' +
            '<div class="zi-panel-body">' +
              '<div class="zi-format-grid">' +
                '<div class="zi-format"><b>Text Polygon</b><br>Название + 3 и более координат</div>' +
                '<div class="zi-format"><b>KML</b><br>&lt;coordinates&gt;lon,lat lon,lat&lt;/coordinates&gt;</div>' +
                '<div class="zi-format"><b>GeoJSON</b><br>Polygon / MultiPolygon</div>' +
                '<div class="zi-format"><b>Local</b><br>Сохраняется в памяти браузера</div>' +
              '</div>' +
              '<div class="zi-kpi-grid">' +
                '<div class="zi-kpi"><span>Зон</span><b id="zi-kpi-zones">0</b></div>' +
                '<div class="zi-kpi"><span>Точек</span><b id="zi-kpi-points">0</b></div>' +
                '<div class="zi-kpi"><span>Площадь</span><b id="zi-kpi-area">—</b></div>' +
              '</div>' +
              '<button class="zi-btn primary" id="zi-save">Сохранить / в зоны</button>' +
            '</div>' +
          '</div>' +
        '</section>' +

        '<section class="zi-panel">' +
          '<div class="zi-panel-head">Распознанные зоны</div>' +
          '<div class="zi-panel-body">' +
            '<div class="zi-table-wrap">' +
              '<table class="zi-table">' +
                '<thead><tr><th>#</th><th>Зона</th><th>Тип</th><th>Точек</th><th>км²</th><th>Перим. км</th></tr></thead>' +
                '<tbody id="zi-table-body"></tbody>' +
              '</table>' +
            '</div>' +
          '</div>' +
        '</section>' +

        '<section class="zi-panel">' +
          '<div class="zi-panel-head">Лог</div>' +
          '<div class="zi-panel-body"><div class="zi-log" id="zi-log">ZONE IMPORT READY\\nВставь зоны и нажми «Распознать».\\n</div></div>' +
        '</section>' +

        '<div class="zi-note"><b>Важно:</b> это локальный импорт. Он не подключается к базе Aircom и не заменяет официальные аэронавигационные данные. Для реальных полётов проверяй актуальные источники.</div>' +
      '</div>';

    scroll.appendChild(page);
    bindZoneButtons();
  }

  function bindZoneButtons(){
    var buttons = [
      ["zi-parse", parseZones],
      ["zi-example", fillExample],
      ["zi-copy", copyZones],
      ["zi-clear", clearZones],
      ["zi-save", saveZones]
    ];

    buttons.forEach(function(pair){
      var b = el(pair[0]);
      if(b && !b.dataset.bound){
        b.dataset.bound = "1";
        b.addEventListener("click", pair[1]);
      }
    });

    var input = el("zi-input");
    if(input && !input.dataset.bound){
      input.dataset.bound = "1";
      input.addEventListener("input", function(){
        clearTimeout(input._ziTimer);
        input._ziTimer = setTimeout(parseZones, 700);
      });
    }
  }

  function addNavButton(){
    if(document.querySelector('.retro-nav-btn[data-tab="zone-import"]')) return;

    var nav = document.querySelector(".retro-nav");
    if(!nav) return;

    var btn = document.createElement("button");
    btn.className = "retro-nav-btn";
    btn.setAttribute("data-tab","zone-import");
    btn.innerHTML = '<span class="ico">▧</span><span><b>Импорт зон</b><small>KML / GeoJSON</small></span>';

    btn.addEventListener("click", function(){
      if(typeof window.showTab === "function"){
        window.showTab("zone-import");
      }else{
        document.querySelectorAll(".page").forEach(function(p){ p.classList.remove("active"); });
        var page = el("tab-zone-import");
        if(page) page.classList.add("active");
      }
      highlight("zone-import");
    });

    var zonesBtn = document.querySelector('.retro-nav-btn[data-tab="zones"]');
    if(zonesBtn && zonesBtn.parentNode === nav && zonesBtn.nextSibling){
      nav.insertBefore(btn, zonesBtn.nextSibling);
    }else{
      nav.appendChild(btn);
    }
  }

  function highlight(tab){
    document.querySelectorAll(".retro-nav-btn").forEach(function(b){
      b.classList.toggle("active", b.getAttribute("data-tab") === tab);
    });
  }

  function patchShowTab(){
    if(window.__zoneImportShowTabPatched) return;
    window.__zoneImportShowTabPatched = true;

    if(typeof window.showTab === "function"){
      var oldShowTab = window.showTab;
      window.showTab = function(t){
        ensureZoneImportTab();
        ensureZoneDisplayPanel();
        var result = oldShowTab.apply(this, arguments);

        if(t === "zone-import"){
          document.querySelectorAll(".page").forEach(function(p){
            p.classList.toggle("active", p.id === "tab-zone-import");
          });
          highlight("zone-import");
          var scroll = document.querySelector(".scroll");
          if(scroll) scroll.scrollTop = 0;
        }

        if(t === "zones"){
          setTimeout(renderSavedZones, 80);
        }

        return result;
      };
    }
  }

  function getSavedZones(){
    try{
      var raw = localStorage.getItem("aviscalc_imported_zones_json");
      if(!raw) return [];
      var arr = JSON.parse(raw);
      return Array.isArray(arr) ? arr : [];
    }catch(e){
      return [];
    }
  }

  function ensureZoneDisplayPanel(){
    var zonesTab = el("tab-zones");
    if(!zonesTab || el("zone-display-panel")) return;

    var panel = document.createElement("section");
    panel.className = "zone-display-panel";
    panel.id = "zone-display-panel";
    panel.innerHTML =
      '<div class="zone-display-head"><span>Импортированные зоны</span><small id="zd-status">нет данных</small></div>' +
      '<div class="zone-display-body" id="zd-body">' +
        '<div class="zone-empty"><b>Нет импортированных зон.</b><br>Открой «Импорт зон», вставь KML/GeoJSON/координаты и нажми «Сохранить / в зоны».</div>' +
      '</div>';

    zonesTab.insertBefore(panel, zonesTab.firstChild);
  }

  function renderSavedZones(){
    ensureZoneDisplayPanel();

    var body = el("zd-body");
    if(!body) return;

    var zones = getSavedZones();
    var status = el("zd-status");

    if(!zones.length){
      if(status) status.textContent = "нет данных";
      body.innerHTML = '<div class="zone-empty"><b>Нет импортированных зон.</b><br>Открой «Импорт зон», вставь KML/GeoJSON/координаты и нажми «Сохранить / в зоны».</div>';
      return;
    }

    if(status) status.textContent = zones.length + " зон";

    var rows = "";
    var totalArea = 0;

    zones.forEach(function(z,i){
      var pts = z.points || [];
      var area = polygonAreaKm2(pts);
      var per = polygonPerimeter(pts);
      totalArea += area;
      rows += '<tr>' +
        '<td>'+(i+1)+'</td>' +
        '<td>'+escapeHtml(z.name || ("ZONE-"+(i+1)))+'</td>' +
        '<td>'+escapeHtml(z.type || "LOCAL")+'</td>' +
        '<td class="num">'+pts.length+'</td>' +
        '<td class="num">'+area.toFixed(1)+'</td>' +
        '<td class="num">'+per.toFixed(1)+'</td>' +
      '</tr>';
    });

    body.innerHTML =
      '<div class="zi-kpi-grid">' +
        '<div class="zi-kpi"><span>Зон</span><b>'+zones.length+'</b></div>' +
        '<div class="zi-kpi"><span>Площадь</span><b>'+totalArea.toFixed(1)+' км²</b></div>' +
        '<div class="zi-kpi"><span>Источник</span><b>LOCAL</b></div>' +
      '</div>' +
      '<div class="zi-table-wrap">' +
        '<table class="zi-table">' +
          '<thead><tr><th>#</th><th>Зона</th><th>Тип</th><th>Точек</th><th>км²</th><th>Перим. км</th></tr></thead>' +
          '<tbody>'+rows+'</tbody>' +
        '</table>' +
      '</div>' +
      '<div class="zi-actions">' +
        '<button class="zi-btn primary" id="zd-refresh">Обновить</button>' +
        '<button class="zi-btn warn" id="zd-clear">Очистить зоны</button>' +
      '</div>';

    var refresh = el("zd-refresh");
    var clear = el("zd-clear");

    if(refresh) refresh.addEventListener("click", renderSavedZones);
    if(clear) clear.addEventListener("click", function(){
      try{ localStorage.removeItem("aviscalc_imported_zones_json"); }catch(e){}
      renderSavedZones();
    });
  }

  function escapeHtml(s){
    return String(s).replace(/[&<>"']/g, function(c){
      return {"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c];
    });
  }

  function init(){
    ensureZoneImportTab();
    ensureZoneDisplayPanel();
    addNavButton();
    patchShowTab();
    updateZoneStats();
    renderSavedZones();
    log("Модуль импорта зон загружен.");
  }

  if(document.readyState === "loading"){
    document.addEventListener("DOMContentLoaded", init);
  }else{
    init();
  }
})();

// ===== block =====

(function(){
  var DB_NAME = "AvisCalcAIPDB";
  var DB_VERSION = 1;
  var STORE = "pdfs";
  var indexKey = "aviscalc_aip_index_v1";
  var db = null;
  var selectedFile = null;

  function el(id){ return document.getElementById(id); }

  function log(msg){
    var box = el("aip-log");
    if(!box) return;
    var time = new Date().toLocaleTimeString();
    box.textContent += "[" + time + "] " + msg + "\n";
    box.scrollTop = box.scrollHeight;
  }

  function setText(id, val){
    var x = el(id);
    if(x) x.textContent = val;
  }

  function uid(){
    return "aip-" + Date.now() + "-" + Math.random().toString(16).slice(2);
  }

  function openDb(cb){
    if(db){
      cb(null, db);
      return;
    }

    if(!window.indexedDB){
      cb(new Error("IndexedDB недоступен в этом браузере."));
      return;
    }

    var req = indexedDB.open(DB_NAME, DB_VERSION);

    req.onerror = function(){
      cb(new Error("Не удалось открыть IndexedDB."));
    };

    req.onupgradeneeded = function(e){
      var d = e.target.result;
      if(!d.objectStoreNames.contains(STORE)){
        d.createObjectStore(STORE, { keyPath:"id" });
      }
    };

    req.onsuccess = function(e){
      db = e.target.result;
      cb(null, db);
    };
  }

  function getIndex(){
    try{
      var raw = localStorage.getItem(indexKey);
      if(!raw) return [];
      var arr = JSON.parse(raw);
      return Array.isArray(arr) ? arr : [];
    }catch(e){
      return [];
    }
  }

  function saveIndex(arr){
    localStorage.setItem(indexKey, JSON.stringify(arr || []));
  }

  function storePdf(id, file, cb){
    openDb(function(err, d){
      if(err){ cb(err); return; }

      try{
        var tx = d.transaction(STORE, "readwrite");
        var st = tx.objectStore(STORE);
        var item = {
          id:id,
          name:file.name,
          type:file.type || "application/pdf",
          size:file.size,
          blob:file,
          createdAt:new Date().toISOString()
        };
        var req = st.put(item);
        req.onerror = function(){ cb(new Error("Не удалось сохранить PDF.")); };
        req.onsuccess = function(){ cb(null); };
      }catch(e){
        cb(e);
      }
    });
  }

  function getPdf(id, cb){
    openDb(function(err, d){
      if(err){ cb(err); return; }

      try{
        var tx = d.transaction(STORE, "readonly");
        var st = tx.objectStore(STORE);
        var req = st.get(id);
        req.onerror = function(){ cb(new Error("Не удалось прочитать PDF.")); };
        req.onsuccess = function(){
          cb(null, req.result || null);
        };
      }catch(e){
        cb(e);
      }
    });
  }

  function deletePdf(id, cb){
    openDb(function(err, d){
      if(err){ cb(err); return; }

      try{
        var tx = d.transaction(STORE, "readwrite");
        var st = tx.objectStore(STORE);
        var req = st.delete(id);
        req.onerror = function(){ cb(new Error("Не удалось удалить PDF.")); };
        req.onsuccess = function(){ cb(null); };
      }catch(e){
        cb(e);
      }
    });
  }

  function ensureAipTab(){
    if(el("tab-aip")) return;

    var scroll = document.querySelector(".scroll");
    if(!scroll) return;

    var page = document.createElement("div");
    page.className = "page";
    page.id = "tab-aip";

    page.innerHTML =
      '<div class="aip-manager">' +
        '<section class="aip-hero">' +
          '<div class="aip-hero-content">' +
            '<div class="aip-kicker">ЛОКАЛЬНЫЙ КАТАЛОГ · AIP / PDF / СХЕМЫ</div>' +
            '<div class="aip-title">AIP / Сборники</div>' +
            '<div class="aip-subtitle">Добавляй PDF-схемы, карточки аэродромов и документы АНИ в локальный каталог AvisCalc. Файлы сохраняются в браузере и могут открываться оффлайн на этом устройстве.</div>' +
          '</div>' +
        '</section>' +

        '<section class="aip-grid">' +
          '<div class="aip-panel">' +
            '<div class="aip-panel-head"><span>Добавить PDF</span><small>локально</small></div>' +
            '<div class="aip-panel-body">' +
              '<div class="aip-filebox">' +
                '<input id="aip-file" type="file" accept="application/pdf,.pdf">' +
                '<div class="aip-file-hint" id="aip-file-hint">Выбери PDF-файл: схема аэродрома, страница AIP, сборник или заметка.</div>' +
              '</div>' +

              '<div class="aip-fields">' +
                '<div class="aip-field"><label>ICAO / Код</label><input id="aip-icao" placeholder="например UUDD"></div>' +
                '<div class="aip-field"><label>Тип</label><select id="aip-type"><option>Аэродром</option><option>Схема</option><option>Зона</option><option>Маршрут</option><option>Справка</option><option>Прочее</option></select></div>' +
                '<div class="aip-field full"><label>Название</label><input id="aip-name" placeholder="например Домодедово / IAC RWY 14L"></div>' +
                '<div class="aip-field full"><label>Заметка</label><textarea id="aip-note" placeholder="Частоты, особенности, дата актуальности, комментарий"></textarea></div>' +
              '</div>' +

              '<div class="aip-actions">' +
                '<button class="aip-btn primary" id="aip-save">Добавить</button>' +
                '<button class="aip-btn" id="aip-clear-form">Очистить</button>' +
                '<button class="aip-btn warn" id="aip-export-index">Экспорт индекса</button>' +
              '</div>' +
            '</div>' +
          '</div>' +

          '<div class="aip-panel">' +
            '<div class="aip-panel-head"><span>Каталог</span><small id="aip-count-head">0 файлов</small></div>' +
            '<div class="aip-panel-body">' +
              '<div class="aip-search-row">' +
                '<input class="aip-search" id="aip-search" placeholder="Поиск: ICAO, название, тип, заметка">' +
                '<button class="aip-btn primary" id="aip-refresh">Обновить</button>' +
              '</div>' +
              '<div class="aip-kpi-grid">' +
                '<div class="aip-kpi"><span>Файлов</span><b id="aip-kpi-files">0</b></div>' +
                '<div class="aip-kpi"><span>Размер</span><b id="aip-kpi-size">—</b></div>' +
                '<div class="aip-kpi"><span>Оффлайн</span><b>LOCAL</b></div>' +
              '</div>' +
              '<div class="aip-list" id="aip-list"></div>' +
            '</div>' +
          '</div>' +
        '</section>' +

        '<section class="aip-panel">' +
          '<div class="aip-panel-head"><span>Лог</span><small>storage</small></div>' +
          '<div class="aip-panel-body"><div class="aip-log" id="aip-log">AIP MANAGER READY\\nДобавь PDF-файл и заполни карточку.\\n</div></div>' +
        '</section>' +

        '<div class="aip-note"><b>Важно:</b> PDF сохраняются локально в браузере этого устройства. Если очистить данные Safari/браузера, файлы могут пропасть. Для реальных полётов проверяй актуальность сборников и официальных источников.</div>' +
      '</div>';

    scroll.appendChild(page);
    bindAipButtons();
  }

  function addNavButton(){
    if(document.querySelector('.retro-nav-btn[data-tab="aip"]')) return;

    var nav = document.querySelector(".retro-nav");
    if(!nav) return;

    var btn = document.createElement("button");
    btn.className = "retro-nav-btn";
    btn.setAttribute("data-tab","aip");
    btn.innerHTML = '<span class="ico">▤</span><span><b>AIP</b><small>Сборники PDF</small></span>';

    btn.addEventListener("click", function(){
      if(typeof window.showTab === "function"){
        window.showTab("aip");
      }else{
        document.querySelectorAll(".page").forEach(function(p){ p.classList.remove("active"); });
        var page = el("tab-aip");
        if(page) page.classList.add("active");
      }
      highlight("aip");
      renderAipList();
    });

    var zonesBtn = document.querySelector('.retro-nav-btn[data-tab="zones"]');
    if(zonesBtn && zonesBtn.parentNode === nav && zonesBtn.nextSibling){
      nav.insertBefore(btn, zonesBtn.nextSibling);
    }else{
      nav.appendChild(btn);
    }
  }

  function highlight(tab){
    document.querySelectorAll(".retro-nav-btn").forEach(function(b){
      b.classList.toggle("active", b.getAttribute("data-tab") === tab);
    });
  }

  function bindAipButtons(){
    var file = el("aip-file");
    var save = el("aip-save");
    var clear = el("aip-clear-form");
    var refresh = el("aip-refresh");
    var search = el("aip-search");
    var exportBtn = el("aip-export-index");

    if(file && !file.dataset.bound){
      file.dataset.bound = "1";
      file.addEventListener("change", function(){
        selectedFile = file.files && file.files[0] ? file.files[0] : null;
        if(selectedFile){
          var hint = el("aip-file-hint");
          if(hint) hint.textContent = selectedFile.name + " · " + formatBytes(selectedFile.size);

          if(!el("aip-name").value){
            el("aip-name").value = selectedFile.name.replace(/\.pdf$/i,"");
          }
        }
      });
    }

    if(save && !save.dataset.bound){
      save.dataset.bound = "1";
      save.addEventListener("click", saveAipItem);
    }

    if(clear && !clear.dataset.bound){
      clear.dataset.bound = "1";
      clear.addEventListener("click", clearForm);
    }

    if(refresh && !refresh.dataset.bound){
      refresh.dataset.bound = "1";
      refresh.addEventListener("click", renderAipList);
    }

    if(search && !search.dataset.bound){
      search.dataset.bound = "1";
      search.addEventListener("input", renderAipList);
    }

    if(exportBtn && !exportBtn.dataset.bound){
      exportBtn.dataset.bound = "1";
      exportBtn.addEventListener("click", exportIndex);
    }
  }

  function saveAipItem(){
    var file = selectedFile;
    if(!file){
      log("Сначала выбери PDF-файл.");
      return;
    }

    var name = (el("aip-name").value || file.name).trim();
    var icao = (el("aip-icao").value || "").trim().toUpperCase();
    var type = (el("aip-type").value || "Прочее").trim();
    var note = (el("aip-note").value || "").trim();

    var id = uid();

    log("Сохраняю PDF: " + file.name);

    storePdf(id, file, function(err){
      if(err){
        log("Ошибка: " + err.message);
        return;
      }

      var index = getIndex();
      index.push({
        id:id,
        fileName:file.name,
        name:name,
        icao:icao,
        type:type,
        note:note,
        size:file.size,
        createdAt:new Date().toISOString()
      });
      saveIndex(index);

      log("Добавлено в каталог: " + name);
      clearForm();
      renderAipList();
    });
  }

  function clearForm(){
    selectedFile = null;

    var ids = ["aip-icao","aip-name","aip-note"];
    ids.forEach(function(id){
      var x = el(id);
      if(x) x.value = "";
    });

    var f = el("aip-file");
    if(f) f.value = "";

    var hint = el("aip-file-hint");
    if(hint) hint.textContent = "Выбери PDF-файл: схема аэродрома, страница AIP, сборник или заметка.";
  }

  function renderAipList(){
    var box = el("aip-list");
    if(!box) return;

    var index = getIndex();
    var q = el("aip-search") ? el("aip-search").value.trim().toLowerCase() : "";

    var filtered = index.filter(function(item){
      if(!q) return Trueish();
      var hay = [
        item.name, item.icao, item.type, item.note, item.fileName
      ].join(" ").toLowerCase();
      return hay.indexOf(q) !== -1;
    });

    var totalSize = index.reduce(function(sum, item){ return sum + (Number(item.size) || 0); }, 0);
    setText("aip-kpi-files", index.length);
    setText("aip-kpi-size", formatBytes(totalSize));
    setText("aip-count-head", index.length + " файлов");

    if(!filtered.length){
      box.innerHTML = '<div class="aip-empty"><b>Нет PDF в каталоге.</b><br>Добавь PDF-файл слева или измени поисковый запрос.</div>';
      return;
    }

    box.innerHTML = "";

    filtered.sort(function(a,b){
      return String(b.createdAt || "").localeCompare(String(a.createdAt || ""));
    }).forEach(function(item){
      var card = document.createElement("article");
      card.className = "aip-card";
      card.innerHTML =
        '<div class="aip-card-top">' +
          '<div>' +
            '<div class="aip-card-title">' + escapeHtml(item.name || item.fileName || "PDF") + '</div>' +
            '<div class="aip-card-icao">' + escapeHtml(item.icao || "NO ICAO") + ' · ' + escapeHtml(item.fileName || "") + '</div>' +
          '</div>' +
          '<div class="aip-badge">' + escapeHtml(item.type || "PDF") + '</div>' +
        '</div>' +
        '<div class="aip-card-meta">' +
          'Размер: ' + formatBytes(item.size || 0) + '<br>' +
          'Добавлено: ' + formatDate(item.createdAt) + '<br>' +
          (item.note ? 'Заметка: ' + escapeHtml(item.note) : 'Заметка: —') +
        '</div>' +
        '<div class="aip-card-actions">' +
          '<button class="aip-mini-btn primary" data-aip-open="' + item.id + '">Открыть</button>' +
          '<button class="aip-mini-btn" data-aip-info="' + item.id + '">Инфо</button>' +
          '<button class="aip-mini-btn danger" data-aip-delete="' + item.id + '">Удалить</button>' +
        '</div>';
      box.appendChild(card);
    });

    bindCardButtons();
  }

  function Trueish(){ return true; }

  function bindCardButtons(){
    document.querySelectorAll("[data-aip-open]").forEach(function(btn){
      if(btn.dataset.bound) return;
      btn.dataset.bound = "1";
      btn.addEventListener("click", function(){
        openPdf(btn.getAttribute("data-aip-open"));
      });
    });

    document.querySelectorAll("[data-aip-delete]").forEach(function(btn){
      if(btn.dataset.bound) return;
      btn.dataset.bound = "1";
      btn.addEventListener("click", function(){
        deleteAipItem(btn.getAttribute("data-aip-delete"));
      });
    });

    document.querySelectorAll("[data-aip-info]").forEach(function(btn){
      if(btn.dataset.bound) return;
      btn.dataset.bound = "1";
      btn.addEventListener("click", function(){
        showInfo(btn.getAttribute("data-aip-info"));
      });
    });
  }

  function openPdf(id){
    getPdf(id, function(err, item){
      if(err){
        log("Ошибка открытия: " + err.message);
        return;
      }

      if(!item || !item.blob){
        log("PDF не найден в IndexedDB.");
        return;
      }

      try{
        var blob = item.blob;
        var url = URL.createObjectURL(blob);
        window.open(url, "_blank");
        log("Открываю PDF: " + (item.name || id));
        setTimeout(function(){ URL.revokeObjectURL(url); }, 60000);
      }catch(e){
        log("Не удалось открыть PDF: " + e.message);
      }
    });
  }

  function deleteAipItem(id){
    if(!confirm("Удалить PDF из локального каталога?")) return;

    deletePdf(id, function(err){
      if(err) log("Ошибка удаления файла: " + err.message);

      var index = getIndex().filter(function(item){ return item.id !== id; });
      saveIndex(index);
      log("Удалено из каталога.");
      renderAipList();
    });
  }

  function showInfo(id){
    var item = getIndex().filter(function(x){ return x.id === id; })[0];
    if(!item){
      log("Карточка не найдена.");
      return;
    }

    log("PDF INFO:");
    log("ICAO: " + (item.icao || "—"));
    log("Название: " + (item.name || "—"));
    log("Тип: " + (item.type || "—"));
    log("Файл: " + (item.fileName || "—"));
    log("Размер: " + formatBytes(item.size || 0));
    log("Заметка: " + (item.note || "—"));
  }

  function exportIndex(){
    var index = getIndex();
    var data = {
      exportedAt:new Date().toISOString(),
      note:"Это только индекс каталога AIP. PDF-файлы не входят в JSON.",
      items:index
    };

    var blob = new Blob([JSON.stringify(data, null, 2)], {type:"application/json"});
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = "aviscalc_aip_index.json";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(function(){ URL.revokeObjectURL(url); }, 1000);
    log("Индекс каталога экспортирован.");
  }

  function formatBytes(bytes){
    bytes = Number(bytes) || 0;
    if(bytes < 1024) return bytes + " B";
    if(bytes < 1024*1024) return (bytes/1024).toFixed(1) + " KB";
    return (bytes/1024/1024).toFixed(1) + " MB";
  }

  function formatDate(s){
    if(!s) return "—";
    try{
      var d = new Date(s);
      return d.toLocaleDateString() + " " + d.toLocaleTimeString().slice(0,5);
    }catch(e){
      return s;
    }
  }

  function escapeHtml(s){
    return String(s || "").replace(/[&<>"']/g, function(c){
      return {"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c];
    });
  }

  function patchShowTab(){
    if(window.__aipManagerShowTabPatched) return;
    window.__aipManagerShowTabPatched = true;

    if(typeof window.showTab === "function"){
      var oldShowTab = window.showTab;
      window.showTab = function(t){
        ensureAipTab();
        var result = oldShowTab.apply(this, arguments);

        if(t === "aip"){
          document.querySelectorAll(".page").forEach(function(p){
            p.classList.toggle("active", p.id === "tab-aip");
          });
          highlight("aip");
          var scroll = document.querySelector(".scroll");
          if(scroll) scroll.scrollTop = 0;
          renderAipList();
        }

        return result;
      };
    }
  }

  function init(){
    ensureAipTab();
    addNavButton();
    patchShowTab();
    openDb(function(err){
      if(err) log("IndexedDB: " + err.message);
      else log("IndexedDB готова.");
    });
    renderAipList();
  }

  if(document.readyState === "loading"){
    document.addEventListener("DOMContentLoaded", init);
  }else{
    init();
  }
})();

