(function(){
  var caicaLinks = [
    {
      title:"Сборники АНИ",
      badge:"ЦАИ",
      text:"Главная страница сборников аэронавигационной информации ЦАИ.",
      url:"https://www.caica.ru/sborniks/",
      type:"Сборник"
    },
    {
      title:"AIP Российской Федерации",
      badge:"AIP RF",
      text:"Раздел AIP РФ / продукты ЦАИ с официальной аэронавигационной информацией.",
      url:"https://www.caica.ru/products/",
      type:"AIP"
    },
    {
      title:"Загружаемые данные",
      badge:"DATA",
      text:"Раздел ЦАИ с загружаемыми данными и ссылками на актуальные материалы.",
      url:"https://www.caica.ru/dnload/",
      type:"Данные"
    },
    {
      title:"Оперативные изменения",
      badge:"UPD",
      text:"Оперативные изменения к сборникам АНИ и связанные обновления.",
      url:"https://www.caica.ru/OperOMI/",
      type:"Изменения"
    },
    {
      title:"Искусственные препятствия",
      badge:"OBS",
      text:"Сборник аэронавигационных данных об искусственных препятствиях РФ.",
      url:"https://www.caica.ru/obslist/",
      type:"Препятствия"
    },
    {
      title:"Сборники РОССИЯ / СНГ",
      badge:"RU/CIS",
      text:"Страница сборников аэронавигационной информации «РОССИЯ» и «СНГ».",
      url:"https://www.caica.ru/AeroInfoRusCis/",
      type:"Сборник"
    },
    {
      title:"Сборник №11",
      badge:"№11",
      text:"Европейская часть Российской Федерации: список аэродромов и индексов.",
      url:"https://www.caica.ru/list_sbornik_11.php",
      type:"№11"
    }
  ];

  function el(id){ return document.getElementById(id); }

  function ensureCaicaCatalog(){
    var aip = el("tab-aip");
    if(!aip || el("caica-catalog-panel")) return;

    var target = aip.querySelector(".aip-grid");
    if(!target) return;

    var panel = document.createElement("section");
    panel.className = "aip-panel";
    panel.id = "caica-catalog-panel";
    panel.innerHTML =
      '<div class="aip-panel-head"><span>Каталог ЦАИ</span><small>официальные ссылки</small></div>' +
      '<div class="aip-panel-body">' +
        '<div class="caica-catalog">' +
          '<section class="caica-hero">' +
            '<div class="caica-kicker">ОФИЦИАЛЬНЫЕ ИСТОЧНИКИ · CAICA.RU</div>' +
            '<div class="caica-title">Сборники и данные ЦАИ</div>' +
            '<div class="caica-sub">Открой нужный раздел ЦАИ, скачай актуальный PDF/файл и добавь его в локальный каталог AvisCalc через форму «Добавить PDF».</div>' +
          '</section>' +
          '<div class="caica-grid" id="caica-grid"></div>' +
          '<div class="caica-note"><b>Важно:</b> AvisCalc не копирует базу ЦАИ внутрь приложения автоматически. Так данные остаются актуальными: ты сам скачиваешь свежий PDF с официального сайта и добавляешь его в оффлайн-каталог.</div>' +
        '</div>' +
      '</div>';

    aip.insertBefore(panel, target);

    renderCaicaCards();
  }

  function renderCaicaCards(){
    var grid = el("caica-grid");
    if(!grid) return;

    grid.innerHTML = "";

    caicaLinks.forEach(function(item, i){
      var card = document.createElement("article");
      card.className = "caica-card";
      card.innerHTML =
        '<div class="caica-card-top">' +
          '<div class="caica-card-title">' + escapeHtml(item.title) + '</div>' +
          '<div class="caica-badge">' + escapeHtml(item.badge) + '</div>' +
        '</div>' +
        '<div class="caica-card-text">' + escapeHtml(item.text) + '</div>' +
        '<div class="caica-actions">' +
          '<button class="caica-btn primary" data-caica-open="' + i + '">Открыть</button>' +
          '<button class="caica-btn warn" data-caica-template="' + i + '">Заполнить карточку</button>' +
        '</div>';
      grid.appendChild(card);
    });

    bindCaicaButtons();
  }

  function bindCaicaButtons(){
    document.querySelectorAll("[data-caica-open]").forEach(function(btn){
      if(btn.dataset.bound) return;
      btn.dataset.bound = "1";
      btn.addEventListener("click", function(){
        var item = caicaLinks[Number(btn.getAttribute("data-caica-open"))];
        if(item) window.open(item.url, "_blank");
      });
    });

    document.querySelectorAll("[data-caica-template]").forEach(function(btn){
      if(btn.dataset.bound) return;
      btn.dataset.bound = "1";
      btn.addEventListener("click", function(){
        var item = caicaLinks[Number(btn.getAttribute("data-caica-template"))];
        if(item) fillAipTemplate(item);
      });
    });
  }

  function fillAipTemplate(item){
    var type = el("aip-type");
    var name = el("aip-name");
    var note = el("aip-note");

    if(type) type.value = item.type || "Справка";
    if(name) name.value = item.title;
    if(note){
      note.value =
        "Источник: " + item.url + "\n" +
        item.text + "\n" +
        "После скачивания актуального PDF с сайта ЦАИ добавь файл через кнопку выбора PDF.";
    }

    if(typeof log === "function"){
      try{ log("Шаблон ЦАИ добавлен в форму: " + item.title); }catch(e){}
    }

    var file = el("aip-file");
    if(file) file.scrollIntoView({behavior:"smooth", block:"center"});
  }

  function escapeHtml(s){
    return String(s || "").replace(/[&<>"']/g, function(c){
      return {"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c];
    });
  }

  function patchShowTab(){
    if(window.__caicaCatalogShowTabPatched) return;
    window.__caicaCatalogShowTabPatched = true;

    if(typeof window.showTab === "function"){
      var oldShowTab = window.showTab;
      window.showTab = function(t){
        var result = oldShowTab.apply(this, arguments);
        if(t === "aip"){
          setTimeout(ensureCaicaCatalog, 100);
        }
        return result;
      };
    }
  }

  function init(){
    ensureCaicaCatalog();
    patchShowTab();
  }

  if(document.readyState === "loading"){
    document.addEventListener("DOMContentLoaded", init);
  }else{
    init();
  }
})();

